import { useEffect, useState } from 'react';
import axios from 'axios';


const RefereesPage = () => {
  const [referees, setReferees] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchReferees = async () => {
      try {
        const response = await axios.get(`/api/referee/referees`);
        setReferees(response.data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchReferees();
  }, []);


  if (error) return <div className="text-red-500 text-center mt-8">Error: {error}</div>;

  return (
    <div className="min-h-screen bg-gray-50 py-8 px-4 sm:px-6 lg:px-8">
      <div className=" mx-auto">
        <div className="text-center mb-12">
          <h1 className="text-3xl font-bold text-gray-900 sm:text-4xl">Our Referees</h1>
          <p className="mt-3 text-xl text-gray-500">
            Qualified professionals ensuring fair play
          </p>
        </div>

        <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
          {referees.map((referee) => {
            const fullName = `${referee.firstName} ${referee.lastName}`;
            const user = referee.userId || {};

            return (
              <div key={referee._id} className="bg-white overflow-hidden shadow rounded-lg">
                <div className="p-5">
                  <div className="flex items-center">
                    {user.profileImage ? (
                      <img
                        className="h-16 w-16 rounded-full object-cover"
                        src={user.profileImage}
                        alt={fullName}
                      />
                    ) : (
                      <div className="h-16 w-16 rounded-full bg-gray-200 flex items-center justify-center text-gray-500">
                        {fullName.charAt(0)}
                      </div>
                    )}
                    <div className="ml-4">
                      <h3 className="text-lg font-medium text-gray-900">{fullName}</h3>
                      <p className="text-sm text-gray-500">{user.email}</p>
                    </div>
                  </div>
                </div>
                <div className="border-t border-gray-200 px-5 py-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <p className="text-sm font-medium text-gray-500">Certification</p>
                      <p className="text-sm text-gray-900">
                        {referee.certificationLevel || 'Not specified'}
                      </p>
                    </div>
                    <div>
                      <p className="text-sm font-medium text-gray-500">Experience</p>
                      <p className="text-sm text-gray-900">
                        {referee.experience || 0} {referee.experience === 1 ? 'year' : 'years'}
                      </p>
                    </div>
                  </div>
                </div>
                <div className="bg-gray-50 px-5 py-3">
                  <div className="text-sm">
                    {referee.sports && referee.sports.length > 0 ? (
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                        {referee.sports.join(', ')}
                      </span>
                    ) : (
                      <span className="text-gray-500">No sports specified</span>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {referees.length === 0 && (
          <div className="text-center py-12">
            <p className="text-gray-500 text-lg">No referees found</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default RefereesPage;

import React, { useState, useEffect, useContext } from "react";
import {
  FaHeart,
  FaRegHeart,
  FaBookmark,
  FaRegBookmark,
  FaShareAlt,
  FaPlus,
  FaTimes,
} from "react-icons/fa";
import axios from "axios";
import { AuthContext } from "../context/AuthContext";

function CSocial() {
  const { auth } = useContext(AuthContext);
  const userId = auth?._id;
  const token = localStorage.getItem("token");

  // Form state inside modal
  const [tournamentName, setTournamentName] = useState("");
  const [caption, setCaption] = useState("");
  const [link, setLink] = useState("");
  const [location, setLocation] = useState("");

  // Posts state
  const [posts, setPosts] = useState([]);

  // Modal open state
  const [modalOpen, setModalOpen] = useState(false);

  useEffect(() => {
    fetchPosts();
  }, []);

  const fetchPosts = async () => {
    try {
      const res = await axios.get(`/api/posts`);
      setPosts(res.data);
    } catch (err) {
      console.error("Error fetching posts:", err);
    }
  };

  const extractTags = (text) => {
    const matches = text.match(/@(\w+)/g);
    return matches ? matches.map((tag) => tag.slice(1)) : [];
  };

  const handlePostSubmit = async (e) => {
    e.preventDefault();
    if (!caption.trim() && !tournamentName.trim() && !link.trim()) return;
    const tags = extractTags(caption);
    try {
      const res = await axios.post(
        `/api/posts`,
        { tournamentName, caption, tags, location, link },
        {
          headers: { Authorization: `Bearer ${token}` },
        }
      );
      setPosts([res.data, ...posts]);
      // Reset form fields
      setTournamentName("");
      setCaption("");
      setLink("");
      setLocation("");
      // Close modal after submit
      setModalOpen(false);
    } catch (err) {
      console.error("Error creating post:", err.response || err);
      alert(err.response?.data?.message || "Post creation failed");
    }
  };

  const toggleLike = async (postId) => {
    try {
      const res = await axios.post(
        `/api/posts/${postId}/like`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setPosts(posts.map((post) => (post._id === postId ? res.data : post)));
    } catch (err) {
      console.error("Like failed", err);
    }
  };

  const toggleSave = async (postId) => {
    try {
      const res = await axios.post(
        `/api/posts/${postId}/save`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );
      setPosts(posts.map((post) => (post._id === postId ? res.data : post)));
    } catch (err) {
      console.error("Save failed", err);
    }
  };

  const formatDescription = (text) => {
    if (!text) return null;
    const words = text.split(/\s+/);
    return words.map((word, idx) => {
      if (word.startsWith("@")) {
        return (
          <span key={idx} className="text-blue-600 font-medium mr-1">
            {word}{" "}
          </span>
        );
      }
      if (word.startsWith("#")) {
        return (
          <span key={idx} className="text-purple-600 font-medium mr-1">
            {word}{" "}
          </span>
        );
      }
      return word + " ";
    });
  };

  return (
    <div className="min-h-screen bg-gray-50 px-4 py-8 ">
      {/* Floating + button */}
      <button
        onClick={() => setModalOpen(true)}
        className="fixed bottom-6 right-6  text-white w-14 h-14 rounded-full shadow-lg flex items-center justify-center hover:bg-indigo-700 transition"
        aria-label="Create Post"
      >
        <FaPlus size={24} />
      </button>

      {/* Modal Popup */}
      {modalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl max-w-md w-full p-6 relative shadow-lg">
            {/* Modal header with title and close icon inline */}
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-bold text-gray-800 whitespace-nowrap">
                Create a Post
              </h2>

              <button
                onClick={() => setModalOpen(false)}
                className="w-fit h-fit p-1 rounded-full hover:bg-gray-200 focus:outline-none"
                aria-label="Close"
              >
                <FaTimes
                  size={20}
                  className="text-gray-600 hover:text-gray-900"
                />
              </button>
            </div>

            <form onSubmit={handlePostSubmit} className="space-y-4">
              <input
                type="text"
                placeholder="Tournament Name"
                className="w-full p-3 rounded-xl border border-gray-300 focus:outline-none focus:ring focus:ring-indigo-300"
                value={tournamentName}
                onChange={(e) => setTournamentName(e.target.value)}
              />
              <textarea
                rows="3"
                placeholder="Write caption with @tags and #hashtags..."
                className="w-full p-3 rounded-xl border border-gray-300 resize-none focus:outline-none focus:ring focus:ring-indigo-300"
                value={caption}
                onChange={(e) => setCaption(e.target.value)}
              />
              <input
                type="text"
                placeholder="Location (optional)"
                className="w-full p-3 rounded-xl border border-gray-300 focus:outline-none focus:ring focus:ring-indigo-300"
                value={location}
                onChange={(e) => setLocation(e.target.value)}
              />
              <input
                type="text"
                placeholder="Optional Link (https://...)"
                className="w-full p-3 rounded-xl border border-gray-300 focus:outline-none focus:ring focus:ring-indigo-300"
                value={link}
                onChange={(e) => setLink(e.target.value)}
              />
              <button
                type="submit"
                className="w-full bg-gradient-to-r from-indigo-600 to-blue-600 text-white py-3 rounded-xl font-semibold hover:scale-105 transition transform"
              >
                Post
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Posts list */}
      <div className=" mx-auto space-y-6 mt-2">
        {posts.length === 0 ? (
          <div className="text-center text-gray-500 text-lg mt-10">
            No posts yet.
          </div>
        ) : (
          posts.map((post) => (
            <div
              key={post._id}
              className="bg-white p-5 rounded-2xl shadow hover:shadow-md transition border border-gray-100"
            >
              <div className="flex items-center gap-4 mb-4">
                <img
                  src={
                    post.user?.profileImage ||
                    "https://i.pravatar.cc/150?img=22"
                  }
                  alt="avatar"
                  className="w-10 h-10 rounded-full"
                />
                <div>
                  <h3 className="font-semibold text-gray-800">
                    {post.user?.name || "User"}
                  </h3>
                  <p className="text-xs text-gray-500">
                    {new Date(post.createdAt).toLocaleDateString()}
                  </p>
                </div>
              </div>

              {post.tournamentName && (
                <p className="text-sm text-gray-600 mb-1 italic">
                  {post.tournamentName}
                </p>
              )}

              <div className="text-gray-800 text-sm mb-3">
                {formatDescription(post.caption)}
              </div>

              {post.link && (
                <a
                  href={post.link}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-600 text-xs underline block mb-3"
                >
                  {post.link}
                </a>
              )}

              <div className="flex justify-between items-center border-t pt-3 text-sm text-gray-500">
                <p>
                  {post.location && `${post.location} • `}
                  {new Date(post.createdAt).toLocaleDateString()}
                </p>
                <div className="flex gap-4">
                  <button
                    onClick={() => toggleLike(post._id)}
                    className="flex items-center gap-1 group text-[#333] hover:bg-[#DBEAFE]"
                  >
                    <span>{post.likes?.length || 0}</span>
                    {post.likes?.some((like) => like._id === userId) ? (
                      <FaHeart className="text-red-500" />
                    ) : (
                      <FaRegHeart className="text-[#333] group-hover:text-red-500" />
                    )}
                  </button>
                  <button
                    onClick={() => toggleSave(post._id)}
                    className=" items-center gap-1 group text-[#333] hover:bg-[#DBEAFE]"
                  >
                    {post.saves?.some((save) => save._id === userId) ? (
                      <FaBookmark className="text-yellow-500" />
                    ) : (
                      <FaRegBookmark className="text-gray-400 hover:text-yellow-500" />
                    )}
                  </button>
                  <button className="items-center gap-1 group text-[#333] hover:bg-[#DBEAFE]">
                    <FaShareAlt className="text-gray-400 hover:text-blue-500" />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}

export default CSocial;

import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../context/AuthContext";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

const ClubAdminDashboard = () => {
  const { auth } = useContext(AuthContext);
  const [profileData, setProfileData] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchUserData = async () => {
      if (!auth || !auth._id) return;

      setIsLoading(true);
      try {
        const response = await axios.get(
          `/api/user/profile/${auth._id}`,
          {
            headers: {
              Authorization: `Bearer ${localStorage.getItem("token")}`,
            },
          }
        );

        setProfileData(response.data);
      } catch (error) {
        console.error("Error fetching profile:", error);
        toast.error("Failed to load profile data");
      } finally {
        setIsLoading(false);
      }
    };

    fetchUserData();
  }, [auth]);

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-indigo-500"></div>
      </div>
    );
  }

  return (
    <div className="bg-gray-50 min-h-screen">
      <div className=" mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="bg-white shadow rounded-lg overflow-hidden">
          {/* Dashboard Header */}
          <div className="px-6 py-5 border-b border-gray-200">
            <h1 className="text-2xl font-bold text-gray-900">
              Club Admin Dashboard
            </h1>
            <p className="mt-1 text-sm text-gray-500">
              Welcome back, {auth?.name || "Club Admin"}
            </p>
          </div>

          {/* Profile Information */}
          <div className="px-6 py-5">
            <h2 className="text-lg font-medium text-gray-900 mb-4">
              Club Profile
            </h2>

            <div className="bg-gray-50 p-4 rounded-lg mb-5">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-4">
                <div>
                  <h3 className="text-sm font-medium text-gray-500">
                    Club Name
                  </h3>
                  <p className="mt-1 text-sm text-gray-900">
                    {profileData?.name || auth?.name || "Not available"}
                  </p>
                </div>

                <div>
                  <h3 className="text-sm font-medium text-gray-500">
                    Email Address
                  </h3>
                  <p className="mt-1 text-sm text-gray-900">
                    {profileData?.email || auth?.email || "Not available"}
                  </p>
                </div>

                <div>
                  <h3 className="text-sm font-medium text-gray-500">
                    Phone Number
                  </h3>
                  <p className="mt-1 text-sm text-gray-900">
                    {profileData?.mobile || auth?.mobile || "Not available"}
                  </p>
                </div>

                <div>
                  <h3 className="text-sm font-medium text-gray-500">Address</h3>
                  <p className="mt-1 text-sm text-gray-900">
                    {profileData?.address || "Not available"}
                  </p>
                </div>
              </div>
            </div>

            <div className="flex justify-center mt-6">
              <button
                className="inline-flex items-center px-4 py-2 border border-transparent text-sm font-medium rounded-md shadow-sm text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 w-auto"
                onClick={() => toast.info("Edit profile feature coming soon!")}
              >
                Edit Profile
              </button>
            </div>
          </div>

          {/* Quick Stats */}
          <div className="px-6 py-5 border-t border-gray-200">
            <h2 className="text-lg font-medium text-gray-900 mb-4">
              Quick Stats
            </h2>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
              <div className="bg-indigo-50 p-4 rounded-lg">
                <h3 className="text-sm font-medium text-indigo-800">Members</h3>
                <p className="mt-2 text-3xl font-bold text-indigo-600">0</p>
              </div>

              <div className="bg-green-50 p-4 rounded-lg">
                <h3 className="text-sm font-medium text-green-800">Events</h3>
                <p className="mt-2 text-3xl font-bold text-green-600">0</p>
              </div>

              <div className="bg-blue-50 p-4 rounded-lg">
                <h3 className="text-sm font-medium text-blue-800">
                  Tournaments
                </h3>
                <p className="mt-2 text-3xl font-bold text-blue-600">0</p>
              </div>
            </div>
          </div>

          {/* Recent Activity */}
          <div className="px-6 py-5 border-t border-gray-200">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-medium text-gray-900">
                Recent Activity
              </h2>
              <button className="text-sm text-indigo-600 hover:text-indigo-500 bg-transparent hover:bg-transparent">
                View All
              </button>
            </div>

            <div className="bg-gray-50 p-6 rounded-lg text-center">
              <p className="text-gray-500">No recent activity found.</p>
              <button
                className="mt-3 inline-flex items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500"
                onClick={() => toast.info("Create event feature coming soon!")}
              >
                Create Your First Event
              </button>
            </div>
          </div>
        </div>

        {/* Quick Action Buttons */}
        <div className="mt-6 grid grid-cols-1 md:grid-cols-3 gap-5">
          <button
            className="px-4 py-3 bg-white shadow rounded-lg hover:bg-transparent hover:shadow-md transition-shadow duration-200 flex items-center justify-center"
            onClick={() => toast.info("Members management coming soon!")}
          >
            <span className="text-gray-900 font-medium hover:bg-transparent">
              Manage Members
            </span>
          </button>

          <button
            className="px-4 py-3 bg-white shadow rounded-lg hover:bg-transparent hover:shadow-md transition-shadow duration-200 flex items-center justify-center"
            onClick={() => toast.info("Event creation coming soon!")}
          >
            <span className="text-gray-900 font-medium">Create Event</span>
          </button>

          <button
            className="px-4 py-3 bg-white shadow rounded-lg hover:bg-transparent hover:shadow-md transition-shadow duration-200 flex items-center justify-center"
            onClick={() => toast.info("Tournament creation coming soon!")}
          >
            <span className="text-gray-900 font-medium hover:bg-transparent">
              Create Tournament
            </span>
          </button>
        </div>
      </div>
      <ToastContainer position="top-center" />
    </div>
  );
};

export default ClubAdminDashboard;

