        // Filter by date range
        if (startDate) {
          const filterStart = new Date(startDate);
          if (payment.date < filterStart) return false;
        }

        if (endDate) {
          const filterEnd = new Date(endDate);
          filterEnd.setHours(23, 59, 59);
          if (payment.date > filterEnd) return false;
        }

        return true;
