// TournamentCard Component with modal functionality
const TournamentCard = ({ tournament, onViewDetails, onSignInPrompt }) => {
  // Safe getter functions for tournament data
  const getTitle = () => tournament.title || "Unnamed Tournament";
  const getType = () => tournament.type || "";
  const getOrganizerName = () => tournament.organizerName || "Organizer";
  const getEventLocation = () => tournament.eventLocation || "Location TBD";
  const getTournamentFee = () => tournament.tournamentFee || "0";

  const formatDate = (dateString) => {
    if (!dateString) {
      console.warn("Missing date string for tournament:", getTitle());
      return "Date TBD";
    }
    try {
      const options = { year: "numeric", month: "short", day: "numeric" };
      return new Date(dateString).toLocaleDateString(undefined, options);
    } catch (err) {
      console.error("Error formatting date:", dateString, err);
      return "Invalid Date";
    }
  };

  const formatDateBefore = (dateString) => {
    if (!dateString) {
      console.warn(
        "Missing date string for tournament booking close:",
        getTitle()
      );
      return "Date TBD";
    }
    try {
      const options = { year: "numeric", month: "short", day: "numeric" };
      const date = new Date(dateString);
      date.setDate(date.getDate() - 1);
      return date.toLocaleDateString(undefined, options);
    } catch (err) {
      console.error("Error formatting booking close date:", dateString, err);
      return "Invalid Date";
    }
  };

  return (
    <motion.div
      className="rounded-[24px] overflow-hidden bg-white tournament-card cursor-pointer shadow-md"
      onClick={() => onViewDetails(tournament)}
      whileHover={{
        y: -5,
