          src={`/src/assets/card-img.png`}
          alt={tournament.title}
          className="w-full h-[200px] object-cover rounded-t-lg"
          whileHover={{ scale: 1.05 }}
          transition={{ duration: 0.3 }}
        />
        <button
          className="absolute top-3 right-3 bg-white/30 p-2 w-9 rounded-full shadow-md backdrop-blur-[20px] border-0 hover:bg-white/50 transition-colors duration-300"
          onClick={(e) => {
            e.stopPropagation();
            // Share functionality would go here
            alert("Share this tournament");
          }}
        >
          <Share2 className="w-5 h-5 text-white" />
        </button>
      </div>

      {/* Content Section */}
      <div className="p-4">
        <div className="inline-table justify-between items-center mb-[12px]">
          <h2 className="text-[#333] font-roboto text-[16px] font-semibold leading-normal">
            {getTitle()}
          </h2>
          {getType() && (
            <span className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
              ({getType()})
            </span>
          )}
        </div>
        <div>
          <p className="text-[#333] font-roboto text-[16px] font-semibold leading-normal mb-[6px]">
            {getOrganizerName()}
          </p>
          <p className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
            {getEventLocation()}
          </p>
        </div>
        <div className="mt-3 flex justify-between items-end">
          <div>
            <p className="text-[#333] font-roboto text-[16px] font-semibold leading-normal mb-[6px]">
              {formatDate(tournament.selectedDate)}
            </p>
            <p className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
