function LHome() {
  const [tournaments, setTournaments] = useState([]);
  const [turfs, setTurfs] = useState([]);
  const [showAllTournaments, setShowAllTournaments] = useState(false);
  const [showAllTurfs, setShowAllTurfs] = useState(false);
  const [loadingTournaments, setLoadingTournaments] = useState(true);
  const [loadingTurfs, setLoadingTurfs] = useState(true);
  const [activeSlide, setActiveSlide] = useState(0);
  const [error, setError] = useState(null);

  // New state for modals
  const [selectedTournament, setSelectedTournament] = useState(null);
  const [selectedTurf, setSelectedTurf] = useState(null);
  const [showSignInModal, setShowSignInModal] = useState(false);
  const [signInMessage, setSignInMessage] = useState("");

  // Auto-advance slides effect
  useEffect(() => {
    const interval = setInterval(() => {
      setActiveSlide((prev) => (prev === 4 ? 0 : prev + 1));
    }, 6000); // Change slide every 6 seconds

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    // When any modal is open, disable browser scrolling
    if (
      showAllTurfs ||
      showAllTournaments ||
      selectedTournament ||
      selectedTurf ||
      showSignInModal
    ) {
      document.documentElement.style.overflow = "hidden";
      document.body.style.overflow = "hidden";
    } else {
      document.documentElement.style.overflow = "";
      document.body.style.overflow = "";
    }

    // Cleanup function
    return () => {
      document.documentElement.style.overflow = "";
      document.body.style.overflow = "";
    };
  }, [
    showAllTurfs,
    showAllTournaments,
    selectedTournament,
    selectedTurf,
    showSignInModal,
  ]);

  useEffect(() => {
    // Fetch tournaments
    const fetchTournaments = async () => {
      try {
        const response = await fetch("http://localhost:3003/api/tournaments");
        if (!response.ok) {
          throw new Error("Failed to fetch tournaments");
        }
        const data = await response.json();

        // Determine the correct data structure
        const tournamentsData = data.tournaments || data;

        setTournaments(tournamentsData);
      } catch (err) {
        console.error("Error fetching tournaments:", err);
        setError(err.message);
      } finally {
        setLoadingTournaments(false);
      }
    };

    // Fetch turfs
    const fetchTurfs = async () => {
      try {
        const response = await fetch("http://localhost:3003/api/turfs");
        if (!response.ok) {
          throw new Error("Failed to fetch turfs");
        }
        const data = await response.json();

        // Determine the correct data structure
        const turfsData = data.turfs || data;

        setTurfs(turfsData);
      } catch (err) {
        console.error("Error fetching turfs:", err);
        setError(err.message);
      } finally {
        setLoadingTurfs(false);
      }
    };

    fetchTournaments();
    fetchTurfs();
