          <div className="bg-white rounded-lg max-w-6xl w-full max-h-[90vh] overflow-y-auto mx-auto my-8 relative">
            {/* Close button positioned in top-right corner */}
            <button
              onClick={() => setShowAllTournaments(false)}
              className="absolute top-3 right-3 text-gray-500 w-auto hover:text-gray-700 bg-transparent hover:bg-transparent border-0 p-2 rounded-full z-20"
            >
              <X className="w-5 h-5" />
            </button>

            <div className="sticky top-0 bg-white p-4 border-b flex items-center z-10 shadow-sm">
              <h2 className="text-xl font-bold text-[#333]">All Tournaments</h2>
            </div>

            <div className="p-6">
              {loadingTournaments ? (
                <LoadingSpinner />
              ) : error ? (
                <div className="text-red-500 text-center">{error}</div>
              ) : displayTournaments.length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-gray-500">
                    No tournaments available at the moment
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {displayTournaments.map((tournament) => (
                    <motion.div
                      key={tournament._id}
                      whileHover={{
                        y: -5,
                        boxShadow: "0 10px 15px -3px rgba(0, 0, 0, 0.1)",
                      }}
                      transition={{ duration: 0.2 }}
                    >
                      <TournamentCard
                        tournament={tournament}
                        onViewDetails={handleViewTournamentDetails}
                        onSignInPrompt={() =>
                          handleSignInPrompt(
                            "Sign in to register for this tournament."
                          )
                        }
                      />
                    </motion.div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Turfs Overlay */}
      {showAllTurfs && (
        <div className="fixed inset-0 bg-black/50 z-50 overflow-y-auto">
          <div className="bg-white rounded-lg max-w-6xl w-full max-h-[90vh] overflow-y-auto mx-auto my-8 relative">
            {/* Close button positioned in top-right corner */}
            <button
              onClick={() => setShowAllTurfs(false)}
              className="absolute top-3 right-3 text-gray-500 hover:text-gray-700 w-auto bg-transparent hover:bg-transparent border-0 p-2 rounded-full z-20"
            >
              <X className="w-5 h-5" />
            </button>

            <div className="sticky top-0 bg-white p-4 border-b flex items-center z-10 shadow-sm">
              <h2 className="text-xl font-bold text-[#333]">
                All Sports Facilities
              </h2>
            </div>

            <div className="p-6">
              {loadingTurfs ? (
                <LoadingSpinner />
              ) : error ? (
                <div className="text-red-500 text-center">{error}</div>
              ) : displayTurfs.length === 0 ? (
                <div className="text-center py-8">
                  <p className="text-gray-500">
                    No sports facilities available at the moment
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {displayTurfs.map((turf) => (
                    <TurfCard
                      key={turf.id || turf._id}
                      turf={turf}
                      onViewDetails={handleViewTurfDetails}
                      onSignInPrompt={() =>
                        handleSignInPrompt("Sign in to book this facility.")
                      }
                    />
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Tournament Detail Modal */}
      <AnimatePresence>
        {selectedTournament && (
          <TournamentDetailModal
            tournament={selectedTournament}
            onClose={() => setSelectedTournament(null)}
            onSignInPrompt={() =>
              handleSignInPrompt("Sign in to register for this tournament.")
            }
          />
        )}
      </AnimatePresence>

      {/* Turf Detail Modal */}
      <AnimatePresence>
        {selectedTurf && (
          <TurfDetailModal
            turf={selectedTurf}
            onClose={() => setSelectedTurf(null)}
            onSignInPrompt={() =>
              handleSignInPrompt("Sign in to book this facility.")
            }
          />
        )}
      </AnimatePresence>

      {/* Sign In Modal */}
      <AnimatePresence>
        {showSignInModal && (
          <SignInModal
            onClose={() => setShowSignInModal(false)}
            message={signInMessage}
          />
        )}
      </AnimatePresence>
    </div>
  );
}

