import { useState, useEffect } from "react";
import { Search, Bell, User, Sun, X, Menu } from "lucide-react"; // ✅ Fixed import
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import Login from "../components/Login";
import Logo from "../assets/sportapp_logo.svg";

const Navbar = () => {
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState("event");
  const [showLogin, setShowLogin] = useState(false);
  const [query, setQuery] = useState("");
  const [suggestions, setSuggestions] = useState(null);
  const [showPopup, setShowPopup] = useState(false);
  const [selectedResult, setSelectedResult] = useState(null);
  const [menuOpen, setMenuOpen] = useState(false);

  const tabs = ["home", "play", "event", "trainer", "social"];

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      if (query.trim() !== "") {
        axios
          .get(`/api/search?query=${query}`)
          .then((res) => setSuggestions(res.data))
          .catch(() => setSuggestions(null));
      } else {
        setSuggestions(null);
      }
    }, 300);

    return () => clearTimeout(delayDebounce);
  }, [query]);

  const handleSuggestionClick = (item) => {
    setSelectedResult(item);
    setShowPopup(true);
    setSuggestions(null);
    setQuery("");
  };

  return (
    <>
      <nav className="fixed top-0 left-0 right-0 z-50 bg-white/70 backdrop-blur-[5px] shadow-md">
        <div className="flex items-center justify-between px-[30px] lg:px-[120px] py-[6px]">
          {/* Logo and Tabs */}
          <div className="flex gap-[41px] items-center">
            <img src={Logo} alt="Logo" className="w-[45.811px] h-[35.481px]" />

            <ul className="hidden md:flex text-gray-700 font-medium">
              {tabs.map((tab) => (
                <button
                  key={tab}
                  onClick={() => {
                    setActiveTab(tab);
                    if (tab === "home") navigate("/l/home");
                    else if (tab === "play") navigate("/l/turf-content");
                    else if (tab === "event") navigate("/l/event");
                    else if (tab === "trainer") navigate("/l/trainer");
                    else if (tab === "social") navigate("/l/social");
                  }}
                  className={`text-[#333] font-roboto p-[10px] cursor-pointer hover:bg-transparent bg-transparent text-[16px] font-normal leading-normal 
                    ${
                      activeTab === tab
                        ? "text-[#FF6A00] border-b-2  border-[#FF6A00]"
                        : "text-[#333] hover:text-[#FFA366] hover:border-[#FFA366]"
                    }`}
                >
                  {tab.charAt(0).toUpperCase() + tab.slice(1)}
                </button>
              ))}
            </ul>
          </div>

          {/* Search Input + Icons */}
          <div className="flex items-center gap-6">
            <div className="hidden md:flex gap-[24px] text-[#666666] relative">
              <div className="relative">
                <input
                  type="text"
                  placeholder="Search..."
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  className="px-3 py-2 pl-3 pr-10 border rounded-md text-sm w-[200px]"
                />
                <Search className="absolute right-2 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-500" />
              </div>

              {suggestions && (
                <div className="absolute top-[40px] left-0 w-full bg-white border rounded-md shadow-lg z-50">
                  {Object.values(suggestions).every(
                    (arr) => arr.length === 0
                  ) ? (
                    <div className="p-2 text-sm text-gray-500">
                      No results found
                    </div>
                  ) : (
                    <>
                      {["users", "turfs", "tournaments", "trainers"].map(
                        (key) =>
                          suggestions[key]?.map((item) => (
                            <div
                              key={item._id}
                              className="p-2 hover:bg-gray-100 cursor-pointer text-sm"
                              onClick={() => handleSuggestionClick(item)}
                            >
                              {item.name}
                            </div>
                          ))
                      )}
                    </>
                  )}
                </div>
              )}
            </div>

            <User
              className="w-[24px] h-[24px] cursor-pointer"
              onClick={() => setShowLogin(true)}
            />
          </div>

          {/* Mobile Menu Toggle */}
          <div className="md:hidden">
            {menuOpen ? (
              <X
                className="w-6 h-6 cursor-pointer"
                onClick={() => setMenuOpen(false)}
              />
            ) : (
              <Menu
                className="w-6 h-6 cursor-pointer"
                onClick={() => setMenuOpen(true)}
              />
            )}
          </div>
        </div>
      </nav>

      {/* Mobile Menu */}
      {menuOpen && (
        <div className="fixed top-[40px] left-0 right-0 bg-white shadow-md z-40 md:hidden px-6 py-4">
          <ul className="flex flex-col gap-3">
            {tabs.map((tab) => (
              <button
                key={tab}
                onClick={() => {
                  setActiveTab(tab);
                  setMenuOpen(false);
                  if (tab === "home") navigate("/l/home");
                  else if (tab === "play") navigate("/l/turf-content");
                  else if (tab === "event") navigate("/l/event");
                  else if (tab === "trainer") navigate("/l/trainer");
                  else if (tab === "social") navigate("/l/social");
                }}
                className={`text-[#333] text-left px-2 py-1 text-base font-medium bg-transparent hover:bg-transparent
                  ${activeTab === tab ? "text-orange-600 font-semibold" : ""}`}
              >
                {tab.charAt(0).toUpperCase() + tab.slice(1)}
              </button>
            ))}
          </ul>

          {/* <div className="flex gap-4 pt-4 border-t border-gray-100 mt-4 text-[#666666]">
            <Search className="w-5 h-5 cursor-pointer" />
            <Bell className="w-5 h-5 cursor-pointer" />
            <User
              className="w-5 h-5 cursor-pointer"
              onClick={() => {
                setShowLogin(true);
                setMenuOpen(false);
              }}
            />
            <Sun className="w-5 h-5 cursor-pointer text-orange-500" />
          </div> */}
        </div>
      )}

      {/* Login Modal */}
      {showLogin && (
        <>
          {/* <div
            className="absolute inset-0 bg-black/50 backdrop-blur-sm z-50"
            onClick={() => setShowLogin(false)}
          ></div> */}
          <div className="fixed bg-black/50 inset-0 flex items-center justify-center z-50">
            <Login onClose={() => setShowLogin(false)} />
          </div>
        </>
      )}

      {/* Search Result Popup */}
      {showPopup && selectedResult && (
        <>
          <div
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-50"
            onClick={() => setShowPopup(false)}
          ></div>
          <div className="fixed top-1/2 left-1/2 z-50 bg-white p-6 rounded-xl shadow-xl transform -translate-x-1/2 -translate-y-1/2 w-[90%] max-w-[400px]">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-semibold">Search Result</h2>
              <X
                className="w-5 h-5 cursor-pointer text-gray-500"
                onClick={() => setShowPopup(false)}
              />
            </div>
            <div>
              <p>
                <strong>Name:</strong> {selectedResult.name}
              </p>
              {selectedResult.email && (
                <p>
                  <strong>Email:</strong> {selectedResult.email}
                </p>
              )}
              {selectedResult.description && (
                <p>
                  <strong>Description:</strong> {selectedResult.description}
                </p>
              )}
              {selectedResult.address && (
                <p>
                  <strong>Address:</strong> {selectedResult.address}
                </p>
              )}
            </div>
          </div>
        </>
      )}
    </>
  );
};

export default Navbar;

