import React, { useEffect, useState } from "react";
import { Share2 } from "lucide-react";
import { motion } from "framer-motion";

const TournamentsCard = () => {
  const [tournaments, setTournaments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchTournaments = async () => {
      try {
        const response = await fetch(`/api/tournaments`);
        if (!response.ok) {
          throw new Error("Failed to fetch tournaments");
        }
        const data = await response.json();

        setTournaments(data.tournaments || data);
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchTournaments();
  }, []);

  const formatDate = (dateString) => {
    const options = { year: "numeric", month: "short", day: "numeric" };
    return new Date(dateString).toLocaleDateString(undefined, options);
  };

  const formatDateBefore = (dateString) => {
    const options = { year: "numeric", month: "short", day: "numeric" };
    const date = new Date(dateString);
    date.setDate(date.getDate() - 1); // Subtract one day
    return date.toLocaleDateString(undefined, options);
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded">
        Error loading tournaments: {error}
      </div>
    );
  }

  if (!tournaments || tournaments.length === 0) {
    return (
      <div className="text-center py-8">
        <p className="text-gray-500">No tournaments available</p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-4">
      {tournaments.map((tournament) => (
        <motion.div
          key={tournament._id}
          whileHover={{
            boxShadow: "0px 8px 24px rgba(0, 0, 0, 0.12)",
          }}
          transition={{ duration: 0.3, ease: "easeInOut" }}
          className="rounded-[24px] overflow-hidden bg-white cursor-pointer"
        >
          {/* Image Section */}
          <div className="relative h-[250px] overflow-hidden">
            <motion.img
              variants={{
                hover: { scale: 1.05 },
              }}
              transition={{ duration: 0.3, ease: "easeInOut" }}
              src={
                tournament.tournamentLogo
                  ? `/uploads/tournaments/${tournament.tournamentLogo
                      .split("\\")
                      .pop()}`
                  : "/src/assets/card-img.png"
              }
              alt={tournament.title}
              className="w-full h-full object-cover rounded-[24px]"
            />
            <button className="absolute top-3 right-3 bg-white/30 p-2 w-9 rounded-full shadow-md backdrop-blur-[20px]">
              <Share2 className="w-5 h-5 text-white" />
            </button>
          </div>

          {/* Content Section */}
          <div className="p-4">
            <div className="flex justify-between items-center mb-[20px]">
              <h2 className="text-[#333] font-roboto text-[16px] font-semibold leading-normal">
                {tournament.title}
              </h2>
              <span className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
                ({tournament.type})
              </span>
            </div>
            <div className="div">
              <p className="text-[#333] font-roboto text-[16px] font-semibold leading-normal mb-[6px]">
                {tournament.organizerName}
              </p>
              <p className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
                {tournament.eventLocation}
              </p>
            </div>
            <div className="mt-3 flex justify-between items-end">
              <div className="div">
                <p className="text-[#333] font-roboto text-[16px] font-semibold leading-normal mb-[6px]">
                  {formatDate(tournament.selectedDate)}
                </p>
                <p className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
                  {tournament.selectedDate && (
                    <>
                      Booking closes on:{" "}
                      {formatDateBefore(tournament.selectedDate)}
                    </>
                  )}
                </p>
              </div>
              {/* Price Section */}
              <p className="text-[#333] font-roboto text-[14px] font-semibold leading-normal">
                ₹{" "}
                <span className="text-[#333] font-roboto text-[16px] font-semibold leading-normal">
                  {tournament.tournamentFee}/-
                </span>{" "}
                onward
              </p>
            </div>
          </div>
        </motion.div>
      ))}
    </div>
  );
};

export default TournamentsCard;

import React from "react";
import { Star } from "lucide-react";
import { motion } from "framer-motion";
import { FaDirections } from "react-icons/fa";
import Logo from '../assets/turf-card.jpg';

const TurfCards = ({ turf, onTurfClick }) => {
  // Create safe getters for potentially missing data
  const getName = () =>
    turf?.name ||
    "T12 Sports Turf (Football Cricket) , Coaching for different sports.";
  const getDiscount = () => turf?.discount || 20;
  const getRating = () =>
    turf?.ratings?.average ? turf.ratings.average.toFixed(1) : "4.5";

  const getAddress = () => {
    if (!turf?.address) return "Mirchandani Palms, Pimple Saudagar";
    return turf.address.fullAddress || "Address unavailable";
  };

  const getAreaCity = () => {
    if (!turf?.address) return "Pune - 17";

    const area = turf?.address?.area || "";
    const city = turf?.address?.city || "";
    const pincode = turf?.address?.pincode || "";

    let location = "";
    if (area) location += area;
    if (city) {
      if (location) location += ", ";
      location += city;
    }
    if (pincode) {
      if (location) location += " - ";
      location += pincode;
    }

    return location || "Location unavailable";
  };

  const getSports = () => {
    if (!turf?.sports || !Array.isArray(turf.sports)) {
      return [
        { name: "Box Cricket", icon: "/src/assets/sports_cricket.svg" },
        { name: "Football", icon: "/src/assets/sports_soccer.svg" },
        { name: "Badminton", icon: "/src/assets/shuttlecock.svg" },
        { name: "Table Tennis", icon: "/src/assets/ping-pong.svg" },
      ];
    }
    return turf.sports;
  };

  return (
    <motion.div
      className="relative rounded-xl overflow-hidden border border-[#DDD] bg-white cursor-pointer min-h-[300px] h-full"
      onClick={() => onTurfClick && onTurfClick(turf)}
      whileHover={{
        y: -5,
        boxShadow: "0 10px 15px -3px rgba(0, 0, 0, 0.1)",
      }}
      transition={{ duration: 0.2 }}
    >
      {/* Image with Discount Tag */}
      <div className="relative h-[200px] w-full overflow-hidden">
        <motion.img
          whileHover={{ scale: 1.05 }}
          transition={{ duration: 0.3 }}
          src={
            turf?.images?.[0]
              ? `/uploads/${turf.images[0]}`
              : Logo
          }
          alt={getName()}
          className="h-full w-full object-cover"
        />
        {getDiscount() && (
          <div className="absolute top-2 right-2 bg-[#FF6A00] text-white text-sm px-2 py-1 rounded-md font-medium">
            {getDiscount()}% off
          </div>
        )}
      </div>

      {/* Card Content */}
      <div className="p-4 text-black">
        <div className="flex justify-between items-center gap-[16px] mb-[12px]">
          <h3 className="text-base font-semibold text-black leading-tight">
            {getName()}
          </h3>
          <div className="flex items-center gap-1 text-yellow-400">
            <Star className="w-4 h-4 fill-yellow-400" />
            <span className="text-sm text-black">{getRating()}/5</span>
          </div>
        </div>

        <div className="flex justify-between items-center mb-[10px]">
          <p className="text-sm text-black">
            {getAddress()}
            <br />
            {getAreaCity()}
          </p>
            <FaDirections
            className="h-8 w-8 cursor-pointer"
            style={{ color: "#022E54" }}
            onClick={(e) => {
              e.stopPropagation();
              window.open(
                `https://maps.google.com/?q=${getAddress()},${getAreaCity()}`,
                "_blank"
              );
            }}
          />
        </div>

        {/* Chips */}
        <div className="flex flex-wrap gap-2">
          {getSports().map((sport, index) => (
            <span
              key={sport.name || `sport-${index}`}
              className="text-xs text-[#666] border border-gray-300 rounded-full px-[8px] py-1 flex items-center gap-1 mt-2"
            >
              {sport.icon && (
                <img
                  src={sport.icon}
                  alt={sport.name || "Sport"}
                  className="w-[14px] h-[14px]"
                />
              )}
              {sport.name || "Sport"}
            </span>
          ))}
        </div>
      </div>
    </motion.div>
  );
};

export default TurfCards;

import React, { useState } from 'react';
import axios from 'axios';

const AddTurf = () => {
  const [turfData, setTurfData] = useState({
    name: '', about: '', location: '', photos: [], hourlyPrice: '', sports: '',
    offers: '', amenities: '', rules: '', cancellationPolicy: '', contacts: '',
    openTime: '', closeTime: '', reviews: '', bookingSystem: '',
    specialEvents: '', membershipPlans: '', parkingFacility: ''
  });
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setTurfData({ ...turfData, [e.target.name]: e.target.value });
  };

  const handlePhotoUpload = (e) => {
    setTurfData({ ...turfData, photos: Array.from(e.target.files) });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const formData = new FormData();
    Object.keys(turfData).forEach(key => {
      if (key === 'photos') {
        turfData.photos.forEach(photo => formData.append('photos', photo));
      } else {
        formData.append(key, turfData[key]);
      }
    });

    try {
      const response = await axios.post(`/api/turf/turfs/`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      console.log('Turf added successfully:', response.data);
      alert('Turf added successfully!');
      setTurfData({
        name: '', about: '', location: '', photos: [], hourlyPrice: '', sports: '',
        offers: '', amenities: '', rules: '', cancellationPolicy: '', contacts: '',
        openTime: '', closeTime: '', reviews: '', bookingSystem: '',
        specialEvents: '', membershipPlans: '', parkingFacility: ''
      });
    } catch (error) {
      console.error('Error adding turf:', error);
      alert('Failed to add turf. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold mb-4">Add a Turf</h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <label className="block font-bold">Turf Name</label>
        <input type="text" name="name" value={turfData.name} onChange={handleChange} className="border p-2 w-full" required />

        <label className="block font-bold">About Turf</label>
        <textarea name="about" value={turfData.about} onChange={handleChange} className="border p-2 w-full" required></textarea>

        <label className="block font-bold">Location</label>
        <input type="text" name="location" value={turfData.location} onChange={handleChange} className="border p-2 w-full" required />

        <label className="block font-bold">Photos</label>
        <input type="file" multiple onChange={handlePhotoUpload} className="border p-2 w-full" />

        <label className="block font-bold">Hourly Price</label>
        <input type="number" name="hourlyPrice" value={turfData.hourlyPrice} onChange={handleChange} className="border p-2 w-full" />

        <label className="block font-bold">Available Sports</label>
