        if (teamAPoints < 11 && teamBPoints < 11) {
            showModal("Invalid Score", "A player needs at least 11 points to win a set");
            return;
        }

        const pointDiff = Math.abs(teamAPoints - teamBPoints);
        if (pointDiff < 2) {
            showModal("Invalid Score", "There must be at least a 2-point lead to win");
            return;
        }

        // Ensure valid winner
        if (teamAPoints === teamBPoints) {
            showModal("Invalid Score", "Scores cannot be equal");
            return;
        }

        // Save this round/set locally
        const newSet = `${teamAPoints}-${teamBPoints}`;
        setSets((prev) => [...prev, newSet]);

        // Reset points for next set
        setTeamAPoints(0);
        setTeamBPoints(0);

        showModal("Set Saved", `Set ${sets.length + 1} recorded: ${newSet}`);
    };

    const showModal = (title, message) => {
        setModalTitle(title);
        setModalMessage(message);
        setIsModalOpen(true);
    };

    // Helper function to close modal
    const closeModal = () => {
        setIsModalOpen(false);
    };

    const handleOpenSubModal = (teamType) => {
        setSelectedTeam(teamType);
        setShowSubModal(true);
    };

    return (
        <div className="flex h-screen bg-gray-100">
            {/* Left side: Matches List */}
            <div className="w-1/3 border-r bg-white overflow-y-auto">
                <h2 className="text-xl font-bold p-4">Matches</h2>

                {loading ? (
                    <p className="p-4 text-gray-500">Loading matches...</p>
                ) : (
                    (matchesData[activeGroupId] || []).map((match) => (
                        <div
                            key={match._id}
                            className={`p-4 border-b cursor-pointer hover:bg-gray-50 ${selectedMatch?._id === match._id ? "bg-gray-200" : ""
                                }`}
                            onClick={() => setSelectedMatch(match)}
                        >
                            <h3 className="font-semibold">
                                {match.player1?.userName} vs {match.player2?.userName}
                            </h3>
                            <p className="text-sm text-gray-600">Status: {match.status}</p>
                            {match.scores?.length > 0 && (
                                <p className="text-sm text-gray-800">
                                    Scores: {match.scores.map(s => `${s.setOne}${s.setTwo ? ', ' + s.setTwo : ''}${s.setThree ? ', ' + s.setThree : ''}`).join(" | ")}
                                </p>
                            )}
                        </div>
                    ))
                )}

                {(!loading && (!matchesData[activeGroupId] || matchesData[activeGroupId].length === 0)) && (
                    <p className="p-4 text-gray-500">No matches available for this group.</p>
                )}
            </div>

            {/* Right side: Match Details */}
            <div className="flex-1 p-6 overflow-y-auto">
                {selectedMatch ? (
                    <div>
                        <h2 className="text-2xl font-bold mb-4">
                            {selectedMatch.playerA} vs {selectedMatch.playerB}
                        </h2>
                        <p className="text-gray-700 mb-4">Status: {selectedMatch.status}</p>

                        {/* Live Score */}
                        {selectedMatch.liveScore && (
                            <div className="mb-4 bg-gray-200 p-4 rounded">
                                <h3 className="font-semibold mb-2">Live Score</h3>
                                <p>{selectedMatch.liveScore}</p>
                            </div>
                        )}

                        {/* Buttons to open popups */}
                        <div className="flex gap-4">
                            <button
                                onClick={() => setShowManualPopup(true)}
                                className="bg-blue-600 text-white px-4 py-2 rounded"
                            >
                                Manual Scoreboard
                            </button>
                            <button
                                onClick={() => setShowAutomaticPopup(true)}
                                className="bg-green-600 text-white px-4 py-2 rounded"
                            >
                                Automatic Scoreboard
                            </button>
                        </div>
                    </div>
                ) : (
                    <p className="text-gray-500">Select a match to view details</p>
                )}
            </div>
            <div className="min-h-screen bg-black relative flex flex-col justify-center items-center">
                {/* Toggle Switch for Automated or Manual Mode */}
                {!showEditView && (
                    <div className="absolute right-0 top-16 transform rotate-60 bg-blue-900 p-2 rounded-2xl z-10 flex items-center gap-2 mr-40">
                        <Switch
                            checked={isEnabled}
                            onChange={(event) => setIsEnabled(event.target.checked)}
                        />
                        <span className="text-white text-sm font-medium">
                            {isEnabled ? "Auto" : "Manual"}
                        </span>
                    </div>
                )}

                {/* Main Content Container */}
                {showEditView ? (
                    // Edit View
                    <div>
                        {/* Edit Header */}
                        <div className="border-b border-gray-700">
                            <h2 className="text-xl font-semibold text-white text-center p-4">
                                Edit Match Scores
                            </h2>
                        </div>

                        {/* Games List with Scroll */}
                        <div className="overflow-y-auto h-[calc(100vh-200px)] p-4">
                            {matches?.map((matchInfo, setIndex) => {
                                const teamAWins = matchInfo?.score
                                    ? parseInt(matchInfo.score.split("-")[0])
                                    : 0;
                                const teamBWins = matchInfo?.score
                                    ? parseInt(matchInfo.score.split("-")[1])
                                    : 0;

                                return (
                                    <div key={setIndex} className="mb-4">
                                        {/* Set Header */}
                                        <button
                                            className={`
                      w-full flex justify-between items-center p-4 rounded-lg mb-2
                      ${selectedGame === setIndex
                                                    ? "bg-gray-700 border border-blue-500"
                                                    : "bg-gray-800"
                                                }
                    `}
                                            onClick={() => {
                                                setExpandedSets((prev) =>
                                                    prev.includes(setIndex)
                                                        ? prev.filter((id) => id !== setIndex)
                                                        : [...prev, setIndex]
                                                );
                                            }}
                                        >
                                            <div className="space-y-1">
                                                <h3 className="text-white font-medium">
                                                    Set {setIndex + 1}
                                                </h3>
                                                <span className="text-gray-400 text-sm">
                                                    {teamAWins > teamBWins
                                                        ? "Team A Won"
                                                        : teamBWins > teamAWins
                                                            ? "Team B Won"
                                                            : ""}
                                                </span>
                                                {teamAWins + teamBWins > 0 && (
                                                    <p className="text-gray-400 text-sm">
                                                        Score:{" "}
                                                        <span
                                                            className={
                                                                teamAWins > teamBWins
                                                                    ? "text-green-500"
                                                                    : "text-gray-400"
                                                            }
                                                        >
                                                            {teamAWins}
                                                        </span>
                                                        -
                                                        <span
                                                            className={
                                                                teamBWins > teamAWins
                                                                    ? "text-green-500"
                                                                    : "text-gray-400"
                                                            }
                                                        >
                                                            {teamBWins}
                                                        </span>
                                                    </p>
                                                )}
                                            </div>
                                            <div className="flex items-center gap-4">
                                                {teamAWins + teamBWins > 0 && (
                                                    <div className="flex items-center gap-2">
                                                        <span
                                                            className={`text-xl ${teamAWins > teamBWins
                                                                ? "text-green-500"
                                                                : "text-white"
                                                                }`}
                                                        >
                                                            {teamAWins}
                                                        </span>
                                                        <span className="text-white text-xl">-</span>
                                                        <span
                                                            className={`text-xl ${teamBWins > teamAWins
                                                                ? "text-green-500"
                                                                : "text-white"
                                                                }`}
                                                        >
                                                            {teamBWins}
                                                        </span>
                                                    </div>
                                                )}
                                                <span className="text-white text-xl">
                                                    {expandedSets.includes(setIndex) ? "▼" : "▶"}
                                                </span>
                                            </div>
                                        </button>

                                        {/* Games within Set */}
                                        {expandedSets.includes(setIndex) &&
                                            matchInfo?.games?.length > 0 && (
                                                <div className="ml-4 space-y-2">
                                                    {matchInfo.games.map((game, gameIndex) => {
                                                        const scores = game.score?.split("-").map(Number) || [
                                                            0, 0,
                                                        ];
                                                        const isTeamAWinner = scores[0] > scores[1];
                                                        const isSelected =
                                                            selectedGame === `${setIndex}-${gameIndex}`;

                                                        return (
                                                            <button
                                                                key={`${setIndex}-${gameIndex}`}
                                                                className={`
                              w-full flex justify-between items-center p-3 rounded-lg
                              ${isSelected
                                                                        ? "bg-gray-700 border border-blue-500"
                                                                        : "bg-gray-800"
                                                                    }
                            `}
                                                                onClick={() => {
                                                                    setSelectedGame(`${setIndex}-${gameIndex}`);
                                                                    setTeamAPoints(scores[0]);
                                                                    setTeamBPoints(scores[1]);
                                                                }}
                                                            >
                                                                <div>
                                                                    <p className="text-white">
                                                                        Game {gameIndex + 1}
                                                                    </p>
                                                                    <p className="text-gray-400 text-sm">
                                                                        {isTeamAWinner ? teamAName : teamBName} Won
                                                                    </p>
                                                                </div>
                                                                <div className="flex items-center gap-2">
                                                                    <span
                                                                        className={`text-lg ${isTeamAWinner
                                                                            ? "text-green-500"
                                                                            : "text-white"
                                                                            }`}
                                                                    >
                                                                        {scores[0]}
                                                                    </span>
                                                                    <span className="text-white">-</span>
                                                                    <span
                                                                        className={`text-lg ${!isTeamAWinner
                                                                            ? "text-green-500"
                                                                            : "text-white"
                                                                            }`}
                                                                    >
                                                                        {scores[1]}
                                                                    </span>
                                                                </div>
                                                            </button>
                                                        );
                                                    })}
                                                </div>
                                            )}
                                    </div>
                                );
                            })}
                        </div>

                        {/* Score Editor */}
                        {selectedGame !== null && (
                            <div className="fixed bottom-0 left-0 right-0 bg-gray-800 p-4 border-t border-gray-700">
                                <h3 className="text-white font-semibold text-center mb-4">
                                    Edit Game Scores
                                </h3>
                                {(() => {
                                    if (!selectedGame) return null;
                                    const [setIndex, gameIndex] = selectedGame
                                        .split("-")
                                        .map(Number);
                                    const selectedGameScore =
                                        matches[setIndex]?.games[gameIndex]?.score || "0-0";

                                    return (
                                        <>
                                            <div className="flex justify-center gap-8 mb-4">
                                                <div className="text-center">
                                                    <label className="text-white mb-2 block">
                                                        {teamAName}
                                                    </label>
                                                    <input
                                                        type="number"
                                                        className="w-20 h-10 text-center rounded bg-gray-700 text-white border border-gray-600"
                                                        defaultValue={selectedGameScore.split("-")[0]}
                                                        onChange={(e) =>
                                                            setTeamAPoints(parseInt(e.target.value) || 0)
                                                        }
                                                    />
                                                </div>

                                                <div className="text-center">
                                                    <label className="text-white mb-2 block">
                                                        {teamBName}
                                                    </label>
                                                    <input
                                                        type="number"
                                                        className="w-20 h-10 text-center rounded bg-gray-700 text-white border border-gray-600"
                                                        defaultValue={selectedGameScore.split("-")[1]}
                                                        onChange={(e) =>
                                                            setTeamBPoints(parseInt(e.target.value) || 0)
                                                        }
                                                    />
                                                </div>
                                            </div>

                                            <div className="flex justify-center gap-4">
                                                <button
                                                    className="px-6 py-2 rounded bg-red-600 text-white hover:bg-red-700"
                                                    onClick={() => setSelectedGame(null)}
                                                >
                                                    Cancel
                                                </button>
                                                <button
                                                    className="px-6 py-2 rounded bg-green-600 text-white hover:bg-green-700"
                                                    onClick={saveEditedScores}
                                                >
                                                    Save
                                                </button>
                                            </div>
                                        </>
                                    );
                                })()}
                            </div>
                        )}

                        {/* Back to Scoreboard Button */}
                        <button
                            className="fixed top-4 right-4 bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
                            onClick={() => {
                                setShowEditView(false);
                                setSelectedGame(null);
                            }}
                        >
                            Back to Scoreboard
                        </button>
                    </div>
                ) : (
                    <>
                        {isEnabled ? (
                            // Automated Scoreboard
                            <div className="fixed inset-0 bg-black">
                                <div className="flex flex-col md:flex-row h-screen">
                                    {/* Player A Side */}
                                    <div
                                        className={`w-full md:w-1/2 bg-blue-500 relative flex flex-col items-center justify-center border-b md:border-b-0 md:border-r border-black py-6 md:py-0 transition-colors ${tapCooldown ? "opacity-50 cursor-not-allowed" : "active:bg-blue-600"
                                            }`}
                                        onClick={() =>
                                            !route?.params?.viewOnly && !tapCooldown && incrementPlayerA()
                                        }
                                    >
                                        {/* Trophy */}
                                        {(winner === playerAName ||
                                            (route?.params?.viewOnly &&
                                                matchStatus === "COMPLETED" &&
                                                (winner === playerAName || playerASetWins > playerBSetWins))) && (
                                                <div className="absolute top-4 md:top-12 right-4 md:right-12">
                                                    <Trophy className="text-yellow-400 w-8 h-8 md:w-16 md:h-16" />
                                                </div>
                                            )}

                                        {/* Set Wins */}
                                        <div className="absolute top-4 md:top-12 left-4 md:left-12">
                                            <span className="text-4xl md:text-8xl font-bold text-white">
                                                {playerASetWins}
                                            </span>
                                        </div>

                                        {/* Main Score */}
                                        <div className="text-6xl md:text-[12rem] font-bold text-white mb-12">
                                            {playerAPoints < 10 ? `0${playerAPoints}` : playerAPoints}
                                        </div>

                                        {/* Player Name */}
                                        <span className="text-2xl md:text-4xl font-bold text-white mb-12 px-2 text-center">
                                            {playerAName}
                                        </span>

                                        {/* Game Scores */}
                                        <div className="absolute bottom-16 md:bottom-32 right-4 md:right-12">
                                            <div className="space-y-2 md:space-y-4">
                                                {Array.from({ length: 3 }).map((_, index) => {
                                                    const currentSet = setsData[currentSetNumber - 1];
                                                    const game = currentSet?.games?.[index];
                                                    return (
                                                        <span
                                                            key={`gameA${index}`}
                                                            className="text-xl md:text-4xl text-white block text-right font-semibold"
                                                        >
                                                            {game?.status === "COMPLETED"
                                                                ? game.playerAPoints
                                                                : index === currentGameInMatch - 1
                                                                    ? playerAPoints
                                                                    : "0"}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        </div>

                                        {/* Decrement Button */}
                                        {!route?.params?.viewOnly && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    if (!tapCooldown) decrementPlayerA();
                                                }}
                                                className="absolute bottom-4 md:bottom-12 left-4 md:left-12 bg-black/20 p-3 md:p-5 rounded-full hover:bg-black/30"
                                                disabled={tapCooldown}
                                            >
                                                <X className="text-white w-6 h-6 md:w-10 md:h-10" />
                                            </button>
                                        )}
                                    </div>

                                    {/* Player B Side */}
                                    <div
                                        className={`w-full md:w-1/2 bg-red-500 relative flex flex-col items-center justify-center py-6 md:py-0 transition-colors ${tapCooldown ? "opacity-50 cursor-not-allowed" : "active:bg-red-600"
                                            }`}
                                        onClick={() =>
                                            !route?.params?.viewOnly && !tapCooldown && incrementPlayerB()
                                        }
                                    >
                                        {/* Trophy */}
                                        {(winner === playerBName ||
                                            (route?.params?.viewOnly &&
                                                matchStatus === "COMPLETED" &&
                                                (winner === playerBName || playerBSetWins > playerASetWins))) && (
                                                <div className="absolute top-4 md:top-12 left-4 md:left-12">
                                                    <Trophy className="text-yellow-400 w-8 h-8 md:w-16 md:h-16" />
                                                </div>
                                            )}

                                        {/* Set Wins */}
                                        <div className="absolute top-4 md:top-12 right-4 md:right-12">
                                            <span className="text-4xl md:text-8xl font-bold text-white">
                                                {playerBSetWins}
                                            </span>
                                        </div>

                                        {/* Main Score */}
                                        <div className="text-6xl md:text-[12rem] font-bold text-white mb-12">
                                            {playerBPoints < 10 ? `0${playerBPoints}` : playerBPoints}
                                        </div>

                                        {/* Player Name */}
                                        <span className="text-2xl md:text-4xl font-bold text-white mb-12 px-2 text-center">
                                            {playerBName}
                                        </span>

                                        {/* Game Scores */}
                                        <div className="absolute bottom-16 md:bottom-32 left-4 md:left-12">
                                            <div className="space-y-2 md:space-y-4">
                                                {Array.from({ length: 3 }).map((_, index) => {
                                                    const currentSet = setsData[currentSetNumber - 1];
                                                    const game = currentSet?.games?.[index];
                                                    return (
                                                        <span
                                                            key={`gameB${index}`}
                                                            className="text-xl md:text-4xl text-white block font-semibold"
                                                        >
                                                            {game?.status === "COMPLETED"
                                                                ? game.playerBPoints
                                                                : index === currentGameInMatch - 1
                                                                    ? playerBPoints
                                                                    : "0"}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        </div>

                                        {/* Decrement Button */}
                                        {!route?.params?.viewOnly && (
                                            <button
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    if (!tapCooldown) decrementPlayerB();
                                                }}
                                                className="absolute bottom-4 md:bottom-12 right-4 md:right-12 bg-black/20 p-3 md:p-5 rounded-full hover:bg-black/30"
                                                disabled={tapCooldown}
                                            >
                                                <X className="text-white w-6 h-6 md:w-10 md:h-10" />
                                            </button>
                                        )}
                                    </div>
                                </div>

                                {/* Control Buttons */}
                                {!route?.params?.viewOnly && (
                                    <div className="absolute bottom-4 md:bottom-12 left-1/2 transform -translate-x-1/2 flex gap-8 z-10">
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                submitRound();
                                            }}
                                            className="bg-orange-600 text-white px-6 py-3 rounded-full flex items-center gap-2 hover:bg-orange-700 text-xl"
                                            disabled={isButtonDisabled}
                                        >
                                            <Check className="w-6 h-6" />
                                            <span>End Game</span>
                                        </button>
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                resetPoints();
                                            }}
                                            className="bg-gray-600 text-white px-6 py-3 rounded-full flex items-center gap-2 hover:bg-gray-700 text-xl"
                                            disabled={isButtonDisabled}
                                        >
                                            <RefreshCcw className="w-6 h-6" />
                                            <span>Reset</span>
                                        </button>
                                    </div>
                                )}
                            </div>

                        ) : (
                            // Manual Scoreboard
                            <div className="max-w-2xl mx-auto p-6 bg-gray-900 rounded-lg">
                                <h2 className="text-2xl font-bold text-white text-center mb-8">
                                    Manual Scoreboard
                                </h2>

                                {/* Player A Row */}
                                <div className="flex items-center gap-4 mb-6">
                                    <span className="text-white text-lg font-medium w-32">{playerAName}</span>
                                    <div className="flex-1">
                                        <label className="text-gray-400 text-sm block mb-1">Points</label>
                                        <input
                                            type="number"
                                            value={teamAPoints}
                                            onChange={(e) => setTeamAPoints(parseInt(e.target.value) || 0)}
                                            className="w-full bg-gray-800 text-white px-3 py-2 rounded border border-gray-700"
                                            disabled={route?.params?.viewOnly || winner}
                                        />
                                    </div>
                                </div>

                                {/* Player B Row */}
                                <div className="flex items-center gap-4 mb-6">
                                    <span className="text-white text-lg font-medium w-32">{playerBName}</span>
                                    <div className="flex-1">
                                        <label className="text-gray-400 text-sm block mb-1">Points</label>
                                        <input
                                            type="number"
                                            value={teamBPoints}
                                            onChange={(e) => setTeamBPoints(parseInt(e.target.value) || 0)}
                                            className="w-full bg-gray-800 text-white px-3 py-2 rounded border border-gray-700"
                                            disabled={route?.params?.viewOnly || winner}
                                        />
                                    </div>
                                </div>

                                {/* Current Game Info */}
                                <div className="bg-gray-800 p-4 rounded-lg mb-6">
                                    <h3 className="text-white font-medium mb-2">Current Game</h3>
                                    <div className="text-gray-300 text-sm space-y-1">
                                        <p>Set: {sets.length + 1} of {parseInt(setCount)}</p>
                                        <p>Players: {playerAName} vs {playerBName}</p>
                                        <p>Status: {matchStatus || "IN_PROGRESS"}</p>
                                    </div>
                                </div>

                                {/* Saved Sets */}
                                {sets.length > 0 && (
                                    <div className="bg-gray-800 p-4 rounded-lg mb-6">
                                        <h3 className="text-white font-medium mb-2">Saved Sets</h3>
                                        <ul className="text-gray-300 text-sm space-y-1">
                                            {sets.map((set, index) => (
                                                <li key={index}>
                                                    Set {index + 1}: {set}
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}

                                {/* Control Buttons */}
                                <div className="flex justify-center gap-4 mt-8">
                                    <button
                                        onClick={saveEditedScores} // <-- will save this set
                                        disabled={route?.params?.viewOnly || winner}
                                        className="bg-green-600 text-white px-6 py-3 rounded-lg flex items-center gap-2 hover:bg-green-700 transition-colors disabled:bg-gray-600 disabled:cursor-not-allowed"
                                    >
                                        <Check className="w-5 h-5" />
                                        <span>Complete Set</span>
                                    </button>
                                    <button
                                        onClick={resetPoints}
                                        disabled={route?.params?.viewOnly || winner}
                                        className="bg-gray-600 text-white px-6 py-3 rounded-lg flex items-center gap-2 hover:bg-gray-700 transition-colors disabled:bg-gray-500 disabled:cursor-not-allowed"
                                    >
                                        <RefreshCcw className="w-5 h-5" />
                                        <span>Reset</span>
                                    </button>
                                </div>

                                {/* Final Submit Button */}
                                {sets.length === parseInt(setCount) && (
                                    <button
                                        onClick={submitMatch} // <-- will send all sets to backend
                                        className="mt-6 w-full bg-blue-600 text-white py-3 rounded-lg flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors"
                                    >
                                        <Check className="w-5 h-5" />
                                        <span>Submit Match</span>
                                    </button>
                                )}
                            </div>

                        )}
                    </>
                )}
            </div>
            {liveState && (
                <div className="absolute top-4 left-4 bg-black/50 text-white px-4 py-2 rounded-lg z-10">
                    <div className="text-sm space-y-1">
                        <p>
                            Set {currentSetNumber} - Game {currentGameInMatch}
                        </p>
                        <p className="text-xs text-gray-300">
                            Overall: {teamASetWins}-{teamBSetWins}
                        </p>
                        {winner && (
                            <p className="text-yellow-400 font-bold">Winner: {winner}</p>
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

export default MGroupStageMatchesPage;

import React, { useState, useEffect } from "react";
import { X, Trophy } from "lucide-react";
import { useLocation } from "react-router-dom";
import { Switch } from "@mui/material";

const MGroupStageScoreBoard = () => {
    // Core scoreboard state
    const [playerAPoints, setPlayerAPoints] = useState(0);
    const [playerBPoints, setPlayerBPoints] = useState(0);
    const [winner, setWinner] = useState(null);
    const [isButtonDisabled, setIsButtonDisabled] = useState(false);
    const [message, setMessage] = useState("");
    const [playerASetWins, setPlayerASetWins] = useState(0);
    const [playerBSetWins, setPlayerBSetWins] = useState(0);
    const [tapCooldown, setTapCooldown] = useState(false);
    const [currentSetNumber, setCurrentSetNumber] = useState(1);
    const [isEnabled, setIsEnabled] = useState(false);

    // Games tracking within current set
    const [currentSetGames, setCurrentSetGames] = useState({ playerA: 0, playerB: 0 });
    const [currentGameNumber, setCurrentGameNumber] = useState(1);
    const [allSetsGames, setAllSetsGames] = useState([]); // Track games for each completed set

    // Match data
    const [matchData, setMatchData] = useState(null);
    const [loading, setLoading] = useState(false);
    const [matchStatus, setMatchStatus] = useState(null);

    // Match Format Configuration (dynamically loaded from database - NO MORE HARDCODED VALUES!)
    const [matchFormat, setMatchFormat] = useState(null); // Will be loaded from match data

    // Set tracking - using proper array format for backend compatibility
    const [currentSetData, setCurrentSetData] = useState({
        setOne: null,   // [playerA_score, playerB_score]
        setTwo: null,   // [playerA_score, playerB_score]
        setThree: null  // [playerA_score, playerB_score]
    });
    const [completedSets, setCompletedSets] = useState([]);


    // Modal state
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalTitle, setModalTitle] = useState("");
    const [modalMessage, setModalMessage] = useState("");

    // Route parameters
    const location = useLocation();
    const route = {
        params: location.state || {},
    };

    const {
        matchId,
        playerAName = "Player A",
        playerBName = "Player B",
        playerAId,
        playerBId
    } = route.params;

    // Initialize match data on mount
    useEffect(() => {
        if (matchId) {
            initializeMatch();
        }
    }, [matchId]);

    // Initialize match with backend integration
    const initializeMatch = async () => {
        try {
            setLoading(true);
            console.log('Initializing match with ID:', matchId);

            // Get current live state from backend - ONLY auto-init when explicitly starting a match
            const response = await fetch(
                `/api/tournaments/matches/${matchId}/live-state?autoInit=false`
            );

            if (response.ok) {
                const data = await response.json();
                console.log("Live state data:", data);

                const match = data.match;
                if (match) {
                    // Debug: Log complete match structure to understand player data
                    console.log('🔍 Complete match structure:', {
                        matchId: match.matchId,
                        player1: match.player1,
                        player2: match.player2,
                        playerA: match.playerA,
                        playerB: match.playerB,
                        players: match.players
                    });

                    // Debug: Log sample game winner structure
                    if (match.sets && match.sets[0] && match.sets[0].games && match.sets[0].games[0]) {
                        console.log('🎯 Sample game winner structure:', match.sets[0].games[0].winner);
                    }

                    // Load match format configuration - ALWAYS use database values!
                    const matchFormatFromDB = match.matchFormat || {};
                    setMatchFormat({
                        // 🎯 UNIFIED SETS CONFIGURATION - Handle all match types (TournamentMatch, SuperMatch, DirectKnockout)
                        totalSets: matchFormatFromDB.maxSets || matchFormatFromDB.totalSets || 5,
                        setsToWin: matchFormatFromDB.setsToWin || Math.ceil((matchFormatFromDB.maxSets || matchFormatFromDB.totalSets || 5) / 2),
                        maxSets: matchFormatFromDB.maxSets || matchFormatFromDB.totalSets || 5,

                        // 🎯 UNIFIED GAMES CONFIGURATION - Handle all match types
                        totalGames: matchFormatFromDB.maxGames || matchFormatFromDB.totalGames || 5,
                        gamesToWin: matchFormatFromDB.gamesToWin || Math.ceil((matchFormatFromDB.maxGames || matchFormatFromDB.totalGames || 5) / 2),
                        maxGames: matchFormatFromDB.maxGames || matchFormatFromDB.totalGames || 5,

                        pointsToWinGame: matchFormatFromDB.pointsToWinGame || 11,
                        marginToWin: matchFormatFromDB.marginToWin || 2,
                        deuceRule: matchFormatFromDB.deuceRule !== undefined ? matchFormatFromDB.deuceRule : true,
                        maxPointsPerGame: matchFormatFromDB.maxPointsPerGame || null,
                        serviceRule: {
                            pointsPerService: matchFormatFromDB.serviceRule?.pointsPerService || 2,
                            deuceServicePoints: matchFormatFromDB.serviceRule?.deuceServicePoints || 1
                        }
                    });
                    console.log("🎯 Loaded dynamic match format configuration:", matchFormatFromDB);
                    console.log("🔥 Calculated frontend matchFormat:", {
                        totalSets: matchFormatFromDB.maxSets || matchFormatFromDB.totalSets || 5,
                        setsToWin: matchFormatFromDB.setsToWin || Math.ceil((matchFormatFromDB.maxSets || matchFormatFromDB.totalSets || 5) / 2),
                        totalGames: matchFormatFromDB.maxGames || matchFormatFromDB.totalGames || 5,
                        gamesToWin: matchFormatFromDB.gamesToWin || Math.ceil((matchFormatFromDB.maxGames || matchFormatFromDB.totalGames || 5) / 2)
                    });

                    // Update live score
                    if (match.liveScore) {
                        setPlayerAPoints(match.liveScore.player1Points || 0);
                        setPlayerBPoints(match.liveScore.player2Points || 0);
                    }

                    // Update current set and game
                    setCurrentSetNumber(match.currentSet || 1);

                    // Load current set games from backend
                    if (match.sets && Array.isArray(match.sets)) {
                        console.log('🔍 Processing sets data:', {
                            totalSets: match.sets.length,
                            currentSetNumber: match.currentSet,
                            sets: match.sets.map(s => ({
                                setNumber: s.setNumber,
                                status: s.status,
                                gamesCount: s.games?.length || 0
                            }))
                        });

                        const currentSet = match.sets.find(set => set.setNumber === match.currentSet);
                        if (currentSet && currentSet.games) {
                            console.log('🎮 Current set games:', {
                                setNumber: currentSet.setNumber,
                                games: currentSet.games.map(g => ({
                                    gameNumber: g.gameNumber,
                                    status: g.status,
                                    winner: g.winner,
                                    completeWinnerObject: JSON.stringify(g.winner, null, 2)
                                }))
                            });

                            const player1Games = currentSet.games.filter(game => {
                                if (game.status !== 'COMPLETED' || !game.winner) return false;

                                const winnerIdMatch = game.winner.playerId && playerAId &&
                                    game.winner.playerId.toString() === playerAId.toString();
                                const winnerNameMatch = game.winner.playerName === playerAName;

                                return winnerIdMatch || winnerNameMatch;
                            }).length;

                            const player2Games = currentSet.games.filter(game => {
                                if (game.status !== 'COMPLETED' || !game.winner) return false;

                                const winnerIdMatch = game.winner.playerId && playerBId &&
                                    game.winner.playerId.toString() === playerBId.toString();
                                const winnerNameMatch = game.winner.playerName === playerBName;

                                return winnerIdMatch || winnerNameMatch;
                            }).length;

                            console.log('📊 Current set games calculated:', {
                                playerA: player1Games,
                                playerB: player2Games,
                                playerAId: playerAId,
                                playerBId: playerBId,
                                playerAName: playerAName,
                                playerBName: playerBName,
                                completedGamesInCurrentSet: currentSet.games.filter(g => g.status === 'COMPLETED'),
                                gameWinners: currentSet.games.filter(g => g.status === 'COMPLETED').map(g => ({
                                    gameNumber: g.gameNumber,
                                    winnerName: g.winner?.playerName,
                                    winnerId: g.winner?.playerId,
                                    winnerObject: g.winner,
                                    fullWinnerJSON: JSON.stringify(g.winner, null, 2)
                                })),
                                allCompletedSets: match.sets?.filter(s => s.status === 'COMPLETED').map(s => ({
                                    setNumber: s.setNumber,
                                    completedGames: s.games?.filter(g => g.status === 'COMPLETED').map(g => ({
                                        gameNum: g.gameNumber,
                                        winnerData: g.winner
                                    }))
                                }))
                            });

                            // Calculate total games won across all sets (we'll update this after processing all sets)
                            setCurrentGameNumber((currentSet.games.filter(g => g.status === 'COMPLETED').length) + 1);
                        } else {
                            console.log('⚠️ Current set not found or has no games');
                        }

                        // Calculate completed sets from sets data
                        const completedSetsData = match.sets
                            .filter(set => set.status === 'COMPLETED')
                            .map(set => {
                                // Calculate set score from games
                                const player1Games = set.games.filter(game => {
                                    if (game.status !== 'COMPLETED' || !game.winner) return false;

                                    const winnerIdMatch = game.winner.playerId && playerAId &&
                                        game.winner.playerId.toString() === playerAId.toString();
                                    const winnerNameMatch = game.winner.playerName === playerAName;

                                    return winnerIdMatch || winnerNameMatch;
                                }).length;

                                const player2Games = set.games.filter(game => {
                                    if (game.status !== 'COMPLETED' || !game.winner) return false;

                                    const winnerIdMatch = game.winner.playerId && playerBId &&
                                        game.winner.playerId.toString() === playerBId.toString();
                                    const winnerNameMatch = game.winner.playerName === playerBName;

                                    return winnerIdMatch || winnerNameMatch;
                                }).length;

                                return [player1Games, player2Games];
                            });

                        // Store all sets games data for viewing
                        const allSetsGamesData = match.sets.map(set => {
                            const player1Games = set.games.filter(game => {
                                if (game.status !== 'COMPLETED' || !game.winner) return false;

                                const winnerIdMatch = game.winner.playerId && playerAId &&
                                    game.winner.playerId.toString() === playerAId.toString();
                                const winnerNameMatch = game.winner.playerName === playerAName;

                                return winnerIdMatch || winnerNameMatch;
                            }).length;

                            const player2Games = set.games.filter(game => {
                                if (game.status !== 'COMPLETED' || !game.winner) return false;

                                const winnerIdMatch = game.winner.playerId && playerBId &&
                                    game.winner.playerId.toString() === playerBId.toString();
                                const winnerNameMatch = game.winner.playerName === playerBName;

                                return winnerIdMatch || winnerNameMatch;
                            }).length;

                            return {
                                setNumber: set.setNumber,
                                games: [player1Games, player2Games],
                                status: set.status
                            };
                        });

                        console.log('🏆 Completed sets calculated:', completedSetsData);
                        console.log('📈 All sets games data:', allSetsGamesData);

                        // Calculate total games won across ALL sets (completed + current)
                        const totalPlayer1Games = allSetsGamesData.reduce((total, set) => total + set.games[0], 0);
                        const totalPlayer2Games = allSetsGamesData.reduce((total, set) => total + set.games[1], 0);

                        console.log('🎯 Total games calculation:', {
                            totalGamesAllSets: { playerA: totalPlayer1Games, playerB: totalPlayer2Games },
                            allSetsBreakdown: allSetsGamesData.map(s => ({ set: s.setNumber, games: s.games }))
                        });

                        // Set the total games (this is what should show in the Games X/3 labels)
                        setCurrentSetGames({ playerA: totalPlayer1Games, playerB: totalPlayer2Games });

                        setCompletedSets(completedSetsData);
                        setAllSetsGames(allSetsGamesData);
                        calculateSetWins(completedSetsData);
                    }

                    setMatchData(match);
                    setMatchStatus(match.status);

                    // If match is completed, show winner
                    if (match.status === 'COMPLETED' && match.result && match.result.winner) {
                        setWinner(match.result.winner.playerName);
                        console.log('Match completed, winner:', match.result.winner.playerName);
                    } else if (match.status === 'COMPLETED') {
                        console.log('Match completed but no winner data available');
                    }

                    console.log('Match data loaded successfully:', {
                        status: match.status,
                        currentSet: match.currentSet,
                        playerASetWins,
                        playerBSetWins,
                        completedSets: completedSets.length
                    });
                }
            }
        } catch (error) {
            console.error("Error initializing match:", error);
            // Even on error, try to show something meaningful
            setMatchStatus('ERROR');
            setMessage('Failed to load match data');
        } finally {
            setLoading(false);
        }
    };


    // Calculate set wins from completed sets
    const calculateSetWins = (sets) => {
        let playerAWins = 0;
        let playerBWins = 0;

        console.log('🧮 Calculating set wins from:', sets);

        sets.forEach(set => {
            if (set && Array.isArray(set) && set.length === 2) {
                console.log(`Set: ${set[0]} - ${set[1]}`);
                if (set[0] > set[1]) {
                    playerAWins++;
                } else if (set[1] > set[0]) {
                    playerBWins++;
                }
            }
        });

        console.log('🎯 Set wins calculated:', { playerAWins, playerBWins });

        setPlayerASetWins(playerAWins);
        setPlayerBSetWins(playerBWins);
    };

    // Update live score via backend
    const updateLiveScore = async (playerA_points, playerB_points) => {
        try {
            const response = await fetch(
                `/api/tournaments/matches/${matchId}/live-score`,
                {
                    method: "PUT",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        player1Points: playerA_points,
                        player2Points: playerB_points
                    }),
                }
            );

            if (!response.ok) {
                const errorData = await response.json();
                throw new Error(errorData.message || "Failed to update live score");
            }

            const data = await response.json();
            console.log("Live score updated:", data);

            // Check if game is completed (11 points with 2+ point lead)
            checkGameCompletion(playerA_points, playerB_points);

        } catch (error) {
            console.error("Error updating live score:", error);
            throw error;
        }
    };

    // Check if current game is completed using dynamic configuration
    const checkGameCompletion = (playerA_points, playerB_points) => {
        // Safety check: Don't process if matchFormat hasn't loaded yet
        if (!matchFormat) {
            console.log("⚠️ Match format not loaded yet, skipping game completion check");
            return;
        }

        const { pointsToWinGame, marginToWin, deuceRule, maxPointsPerGame } = matchFormat;

        const maxPoints = Math.max(playerA_points, playerB_points);
        const pointDiff = Math.abs(playerA_points - playerB_points);

        // Check max points limit (if configured)
        if (maxPointsPerGame && maxPoints >= maxPointsPerGame) {
            console.log(`Game completed: Max points limit (${maxPointsPerGame}) reached`);
            completeCurrentGame(playerA_points, playerB_points);
            return;
        }

        // Standard completion logic
        if (maxPoints >= pointsToWinGame) {
            if (deuceRule) {
                // With deuce rule: must win by margin
                if (pointDiff >= marginToWin) {
                    console.log(`Game completed: ${pointsToWinGame}+ points with ${marginToWin}+ margin (deuce rule)`);
                    completeCurrentGame(playerA_points, playerB_points);
                }
            } else {
                // Without deuce rule: first to pointsToWinGame wins
                console.log(`Game completed: First to ${pointsToWinGame} points (no deuce rule)`);
                completeCurrentGame(playerA_points, playerB_points);
            }
        }
    };

    // Complete current game and handle set/match progression
    const completeCurrentGame = async (playerA_points, playerB_points) => {
        try {
            const response = await fetch(
                `/api/tournaments/matches/${matchId}/complete-game`,
                {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        finalPlayer1Points: playerA_points,
                        finalPlayer2Points: playerB_points
                    }),
                }
            );

            if (response.ok) {
                const data = await response.json();
                console.log("Game completion response:", data);

                // Reset points for next game
                setPlayerAPoints(0);
                setPlayerBPoints(0);

                // Update current set/game from backend response
                if (data.match) {
                    setCurrentSetNumber(data.match.currentSet || currentSetNumber);

                    // Update current set games tracking
                    if (data.match.sets && Array.isArray(data.match.sets)) {
                        const currentSet = data.match.sets.find(set => set.setNumber === data.match.currentSet);
                        if (currentSet && currentSet.games) {
                            const player1Games = currentSet.games.filter(game => {
                                if (game.status !== 'COMPLETED') return false;

                                // Handle knockout matches with null playerIds
                                if (data.match.player1.playerId && game.winner.playerId) {
                                    return game.winner.playerId.toString() === data.match.player1.playerId.toString();
                                } else {
                                    // Fallback to playerName comparison
                                    const matchPlayer1Name = data.match.player1.playerName || data.match.player1.userName;
                                    return game.winner.playerName === matchPlayer1Name;
                                }
                            }).length;

                            const player2Games = currentSet.games.filter(game => {
                                if (game.status !== 'COMPLETED') return false;

                                // Handle knockout matches with null playerIds
                                if (data.match.player2.playerId && game.winner.playerId) {
                                    return game.winner.playerId.toString() === data.match.player2.playerId.toString();
                                } else {
                                    // Fallback to playerName comparison
                                    const matchPlayer2Name = data.match.player2.playerName || data.match.player2.userName;
                                    return game.winner.playerName === matchPlayer2Name;
                                }
                            }).length;

                            setCurrentSetGames({ playerA: player1Games, playerB: player2Games });
                            setCurrentGameNumber((currentSet.games.filter(g => g.status === 'COMPLETED').length) + 1);
                        }

                        // Recalculate completed sets
                        const completedSetsData = data.match.sets
                            .filter(set => set.status === 'COMPLETED')
                            .map(set => {
                                const player1Games = set.games.filter(game => {
                                    if (game.status !== 'COMPLETED') return false;

                                    // Handle knockout matches with null playerIds
                                    if (data.match.player1.playerId && game.winner.playerId) {
                                        return game.winner.playerId.toString() === data.match.player1.playerId.toString();
                                    } else {
                                        // Fallback to playerName comparison
                                        const matchPlayer1Name = data.match.player1.playerName || data.match.player1.userName;
                                        return game.winner.playerName === matchPlayer1Name;
                                    }
                                }).length;

                                const player2Games = set.games.filter(game => {
                                    if (game.status !== 'COMPLETED') return false;

                                    // Handle knockout matches with null playerIds
                                    if (data.match.player2.playerId && game.winner.playerId) {
                                        return game.winner.playerId.toString() === data.match.player2.playerId.toString();
                                    } else {
                                        // Fallback to playerName comparison
                                        const matchPlayer2Name = data.match.player2.playerName || data.match.player2.userName;
                                        return game.winner.playerName === matchPlayer2Name;
                                    }
                                }).length;

                                return [player1Games, player2Games];
                            });

                        // Update all sets games data
                        const allSetsGamesData = data.match.sets.map(set => {
                            const player1Games = set.games.filter(game => {
                                if (game.status !== 'COMPLETED') return false;

                                // Handle knockout matches with null playerIds
                                if (data.match.player1.playerId && game.winner.playerId) {
                                    return game.winner.playerId.toString() === data.match.player1.playerId.toString();
                                } else {
                                    // Fallback to playerName comparison
                                    const matchPlayer1Name = data.match.player1.playerName || data.match.player1.userName;
                                    return game.winner.playerName === matchPlayer1Name;
                                }
                            }).length;

                            const player2Games = set.games.filter(game => {
                                if (game.status !== 'COMPLETED') return false;

                                // Handle knockout matches with null playerIds
                                if (data.match.player2.playerId && game.winner.playerId) {
                                    return game.winner.playerId.toString() === data.match.player2.playerId.toString();
                                } else {
                                    // Fallback to playerName comparison
                                    const matchPlayer2Name = data.match.player2.playerName || data.match.player2.userName;
                                    return game.winner.playerName === matchPlayer2Name;
                                }
                            }).length;

                            return {
                                setNumber: set.setNumber,
                                games: [player1Games, player2Games],
                                status: set.status
                            };
                        });

                        setCompletedSets(completedSetsData);
                        setAllSetsGames(allSetsGamesData);
                        calculateSetWins(completedSetsData);
                    }
                }

                // Check if match is completed
                if (data.matchCompleted) {
                    // Handle different winner structures for SuperMatch vs regular Match
                    let winnerName = null;

                    if (data.match.winner?.playerName) {
                        // SuperMatch structure: direct winner field
                        winnerName = data.match.winner.playerName;
                    } else if (data.match.result?.winner?.playerName) {
                        // Regular Match structure: result.winner field
                        winnerName = data.match.result.winner.playerName;
                    }

                    if (winnerName) {
                        setWinner(winnerName);
                        setMatchStatus("COMPLETED");
                        showModal("Match Completed!", `${winnerName} wins the match!`);
                        // Sync to points table immediately when match completes
                        syncScoreToPointsTable();
                    }
                } else if (data.setCompleted) {
                    showModal("Set Completed!", `Set ${data.currentSet - 1} completed!`);
                    // Also sync when set completes for real-time updates
                    syncScoreToPointsTable();
                } else {
                    showModal("Game Won!", `Game completed! Next game starting...`);
                    // Sync after every game for live tracking
                    syncScoreToPointsTable();
                }
            } else {
                const errorData = await response.json();
                throw new Error(errorData.message || "Failed to complete game");
            }
        } catch (error) {
            console.error("Error completing game:", error);
            showModal("Error", error.message || "Failed to complete game");
        }
    };

    // The match result is already saved by the completeGame endpoint
    // No need for separate saveMatchResult function

    // Increment Player A score
    const incrementPlayerA = async () => {
        if (route?.params?.viewOnly || winner || isButtonDisabled || tapCooldown)
            return;

        setTapCooldown(true);
        setIsButtonDisabled(true);
        setMessage("Please wait...");

        try {
            const newScore = playerAPoints + 1;
            setPlayerAPoints(newScore);
            await updateLiveScore(newScore, playerBPoints);
        } catch (error) {
            console.error("Error incrementing Player A:", error);
            setPlayerAPoints(playerAPoints);
            showModal("Error", "Failed to update score");
        } finally {
            setTimeout(() => {
                setTapCooldown(false);
                setIsButtonDisabled(false);
                setMessage("");
            }, 800);
        }
    };

    // Increment Player B score
    const incrementPlayerB = async () => {
        if (route?.params?.viewOnly || winner || isButtonDisabled || tapCooldown)
            return;

        setTapCooldown(true);
        setIsButtonDisabled(true);
        setMessage("Please wait...");

        try {
            const newScore = playerBPoints + 1;
            setPlayerBPoints(newScore);
            await updateLiveScore(playerAPoints, newScore);
        } catch (error) {
            console.error("Error incrementing Player B:", error);
            setPlayerBPoints(playerBPoints);
            showModal("Error", "Failed to update score");
        } finally {
            setTimeout(() => {
                setTapCooldown(false);
                setIsButtonDisabled(false);
                setMessage("");
            }, 800);
        }
    };

    // Decrement scores
    const decrementPlayerA = async () => {
        if (playerAPoints > 0) {
            const newScore = playerAPoints - 1;
            setPlayerAPoints(newScore);
            await updateLiveScore(newScore, playerBPoints);
        }
    };

    const decrementPlayerB = async () => {
        if (playerBPoints > 0) {
            const newScore = playerBPoints - 1;
            setPlayerBPoints(newScore);
            await updateLiveScore(playerAPoints, newScore);
        }
    };


    // Enhanced sync function to ensure real-time points table updates
    const syncScoreToPointsTable = async () => {
        try {
            // Skip sync for knockout matches (only sync group stage matches to points table)
            if (matchData?.round && ['pre-quarter', 'quarter-final', 'semi-final', 'final'].includes(matchData.round)) {
                console.log('Skipping points table sync for knockout match');
                return;
            }

            console.log('Syncing match data to Score model for real-time points table updates...');

            // Use the endpoint from groupStageScoreboardController
            const response = await fetch(
                `/api/tournaments/matches/${matchId}/sync-scores`,
                {
                    method: "POST",
                    headers: { "Content-Type": "application/json" }
                }
            );

            if (response.ok) {
                const data = await response.json();
                console.log('✅ Match score synced successfully to Score model:', data);

                // Additional verification - check if score was created/updated
                if (data.success && data.score) {
                    console.log('Score model updated with:', {
                        gamesWonA: data.score.gamesWonA,
                        gamesWonB: data.score.gamesWonB,
                        totalScoreA: data.score.totalScoreA,
                        totalScoreB: data.score.totalScoreB,
                        setOne: data.score.setOne,
                        setTwo: data.score.setTwo,
                        setThree: data.score.setThree
                    });
                }
            } else {
                const errorData = await response.json();
                console.warn('⚠️ Failed to sync match score to Score model:', errorData);
            }
        } catch (error) {
            console.error('❌ Error syncing match score to Score model:', error);
            // Don't show error to user for sync issues, just log for debugging
            // The main match functionality should still work
        }
    };

    // Modal helper
    const showModal = (title, message) => {
        setModalTitle(title);
        setModalMessage(message);
        setIsModalOpen(true);
    };

    if (loading) {
        return (
            <div className="fixed inset-0 bg-black flex items-center justify-center">
                <div className="text-white text-lg md:text-2xl">Loading match...</div>
            </div>
        );
    }

    return (
        <div className="fixed inset-0 bg-black">
            {/* Clean Header */}
            <div className="absolute top-0 left-0 right-0 z-10 bg-black/90 p-3 md:p-4">
                <div className="flex items-center justify-between text-white">
                    {/* Match Status */}
                    <div className="text-lg md:text-xl font-semibold">
                        Set {currentSetNumber} - Game {currentGameNumber}
                    </div>

                    {/* Quick Rules - Only show when matchFormat is loaded */}
                    {matchFormat && (
