          courtNumber: String(courtNumber),
          startTime: new Date(`${today}T${currentTime}:00`).toISOString(),
        });
        currentTime = addMinutes(currentTime, matchInterval);
      }
    }

    try {
      const res = await axios.post(
        `/api/tournaments/matches/create`,
