                  >
                    <h2
                      className={`md:text-[18px] text-[16px] font-[600] mb-0 ${openIndex === roundIndex ? "text-white" : "text-[#333]"
                        }`}
                    >
                      {roundName.charAt(0).toUpperCase() + roundName.slice(1).replace('-', ' ')} ({matches.length} matches)
                    </h2>
                    <span
                      className={`transform transition-transform duration-300 ${openIndex === roundIndex ? "rotate-180 text-white" : "text-[#333]"
                        }`}
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor">
                        <path d="M480-344 240-584l56-56 184 184 184-184 56 56-240 240Z" />
                      </svg>
                    </span>
                  </div>

                  <div
                    className={`overflow-hidden transition-all duration-300 ${openIndex === roundIndex
                      ? "max-h-[1000px] opacity-100"
                      : "max-h-0 opacity-0"
                      }`}
                  >
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-[16px] mt-4 p-3">
                      {matches.map((match) => (
                        <div
                          key={match._id}
                          className={`shadow-md rounded-lg p-4 cursor-pointer ${(match.status === 'completed' || match.status === 'COMPLETED') ? 'bg-green-50 border-l-4 border-green-500' :
                            (match.status === 'in-progress' || match.status === 'IN_PROGRESS') ? 'bg-yellow-50 border-l-4 border-yellow-500' :
                              'bg-[#F2F4F6]'
                            }`}
                          onClick={(e) => {
                            e.stopPropagation();
                            openModal(match);
                          }}
                        >
                          <div className="flex justify-between items-center mb-3">
                            <div className="flex items-center gap-2">
                              <span className="bg-blue-100 text-blue-700 rounded-full text-[12px] font-[500] px-2 py-1">
                                {(match.roundName || match.round || 'Round').toUpperCase()} - M{match.matchNumber || match.bracketPosition}
                              </span>
                              <span className="bg-gray-200 text-gray-700 rounded-full text-[12px] font-[400] px-2 py-1">
                                Court {match.courtNumber || 'TBD'}
                              </span>
                              {(match.status === 'completed' || match.status === 'COMPLETED') && (
                                <span className="bg-green-500 text-white md:text-[12px] sm:text-[10px] px-2 py-1 rounded-full text-xs">
                                  Completed
                                </span>
                              )}
                              {(match.status === 'in-progress' || match.status === 'IN_PROGRESS') && (
                                <span className="bg-yellow-500 text-white md:text-[12px] sm:text-[10px] px-2 py-1 rounded-full text-xs">
                                  In Progress
                                </span>
                              )}
                            </div>
                            <button
                              onClick={(e) => {
                                e.stopPropagation();
                                openModal(match);
                              }}
                              className="text-gray-500 hover:bg-transparent focus:outline-none w-auto bg-transparent"
                            >
                              <FiEdit2 />
                            </button>
                          </div>

                          <p className="text-center text-[#333] text-[14px] font-[400] mb-3">
                            {new Date(match.matchStartTime || match.startTime).toLocaleDateString()} at {new Date(match.matchStartTime || match.startTime).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                          </p>

                          <div className="flex flex-col items-center">
                            <div className="flex items-center gap-3 mb-2">
                              <div className="flex items-center gap-2">
                                {match.player1.playerId?.profileImage ? (
                                  <img
                                    src={`/uploads/profiles/${match.player1.playerId.profileImage}`}
                                    alt={match.player1.playerName}
                                    className="w-8 h-8 rounded-full object-cover"
                                  />
                                ) : (
                                  <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white text-sm font-bold">
                                    {match.player1.playerName?.charAt(0) || '?'}
                                  </div>
                                )}
                                <span className={`font-[500] text-[14px] ${match.winner?.playerId?.toString() === match.player1.playerId?.toString() ? 'text-green-600' : 'text-[#004E93]'
                                  }`}>
                                  {match.player1.playerName}
                                  {match.player1.seed && <span className="text-gray-500 text-xs ml-1">(#{match.player1.seed})</span>}
                                </span>
                              </div>
                            </div>

                            <div className="text-[#333] text-[14px] font-[400] my-1 flex items-center gap-2">
                              VS
                              {match.status === 'completed' && match.score && (
                                <span className="text-xs bg-gray-100 px-2 py-1 rounded">
                                  {match.score.player1Sets}-{match.score.player2Sets}
                                </span>
                              )}
                            </div>

                            <div className="flex items-center gap-3">
                              <div className="flex items-center gap-2">
                                {match.player2.playerId?.profileImage ? (
                                  <img
                                    src={`/uploads/profiles/${match.player2.playerId.profileImage}`}
                                    alt={match.player2.playerName}
                                    className="w-8 h-8 rounded-full object-cover"
                                  />
                                ) : (
                                  <div className="w-8 h-8 rounded-full bg-blue-500 flex items-center justify-center text-white text-sm font-bold">
                                    {match.player2.playerName?.charAt(0) || '?'}
                                  </div>
                                )}
                                <span className={`font-[500] text-[14px] ${match.winner?.playerId?.toString() === match.player2.playerId?.toString() ? 'text-green-600' : 'text-[#004E93]'
                                  }`}>
                                  {match.player2.playerName}
                                  {match.player2.seed && <span className="text-gray-500 text-xs ml-1">(#{match.player2.seed})</span>}
                                </span>
                              </div>
                            </div>

                            {/* Live Score Display for Knockout */}
                            {(match.status === 'in-progress' || match.status === 'IN_PROGRESS') && match.liveScore && (
                              <div className="mt-3 p-2 bg-yellow-50 rounded-lg border border-yellow-200">
                                <div className="text-center">
                                  <div className="text-sm text-yellow-700 font-medium mb-1">Live Score</div>
                                  <div className="text-lg font-bold text-gray-800">
                                    {match.liveScore.player1Points || 0} - {match.liveScore.player2Points || 0}
                                  </div>
                                  <div className="text-xs text-yellow-600 mt-1">
                                    Set {match.currentSet || 1}, Game {match.currentGame || 1}
                                  </div>
                                </div>
                              </div>
                            )}

                            {/* Score Data from Legacy Format for Knockout */}
                            {(match.status === 'completed' || match.status === 'COMPLETED') && match.currentScore && !match.result && (
                              match.currentScore.setOne || match.currentScore.setTwo || match.currentScore.setThree
                            ) && (
                                <div className="mt-3 p-2 bg-green-50 rounded-lg border border-green-200">
                                  <div className="text-center">
                                    <div className="text-sm text-green-700 font-medium mb-1">Knockout Complete</div>
                                    <div className="text-xs space-y-1">
                                      {match.currentScore.setOne && (
                                        <div>Set 1: {Array.isArray(match.currentScore.setOne) ? `${match.currentScore.setOne[0]}-${match.currentScore.setOne[1]}` : match.currentScore.setOne}</div>
                                      )}
                                      {match.currentScore.setTwo && (
                                        <div>Set 2: {Array.isArray(match.currentScore.setTwo) ? `${match.currentScore.setTwo[0]}-${match.currentScore.setTwo[1]}` : match.currentScore.setTwo}</div>
                                      )}
                                      {match.currentScore.setThree && (
                                        <div>Set 3: {Array.isArray(match.currentScore.setThree) ? `${match.currentScore.setThree[0]}-${match.currentScore.setThree[1]}` : match.currentScore.setThree}</div>
                                      )}
                                    </div>
                                    {match.winner && (
                                      typeof match.winner === 'object' ?
                                        (match.winner.playerName || match.winner.name) && (
                                          <div className="text-xs text-green-600 mt-1 font-medium">
                                            Winner: {match.winner.playerName || match.winner.name}
                                          </div>
                                        ) :
                                        match.winner.trim() && (
                                          <div className="text-xs text-green-600 mt-1 font-medium">
                                            Winner: {match.winner}
                                          </div>
                                        )
                                    )}
                                  </div>
                                </div>
                              )}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        )
      }

      {/* 🔹 Modal for Match Generation */}
      {
        isModalOpen && (
          <div className="fixed inset-0 flex items-center justify-center bg-gray-900 bg-opacity-50">
            <div className="bg-white w-96 p-6 rounded-xl shadow-lg">
              <div className="flex justify-between items-center">
                <h3 className="text-lg font-semibold">Match Settings</h3>
                <FiX
                  className="cursor-pointer"
                  onClick={() => setIsModalOpen(false)}
                />
              </div>

              <div className="mt-4">
                <label className="block text-sm font-medium text-gray-700">
                  Court Number
                </label>
                <input
                  type="text"
                  className="w-full border p-2 mt-1"
                  value={courtNumber}
                  onChange={(e) => setCourtNumber(e.target.value)}
                />

                <label className="block text-sm font-medium text-gray-700 mt-3">
                  Match Interval (minutes)
                </label>
                <input
                  type="number"
                  className="w-full border p-2 mt-1"
                  value={matchInterval}
