    setFilteredNotifications((prevNotifications) => {
      const newNotifications = prevNotifications.map((section) => ({
        ...section,
        items: section.items.filter((item) => !selected.includes(item.id)),
      }));
      return newNotifications;
    });
    setSelected([]); // Clear the selected items after deletion
  };

  const clearAllNotifications = () => {
    setFilteredNotifications([]); // Clear the filtered notifications
    setSelected([]); // Optionally clear selected items as well
  };

