import { useState, useEffect } from "react";
import axios from "axios";

const MPayments = ({ tournamentId }) => {
    const manager = JSON.parse(localStorage.getItem("user"));
    const managerId = manager?._id;

    const [existingSetup, setExistingSetup] = useState({
        qrCodes: [],
        upiIds: [],
        offlinePayments: [],
    });
    const [newUpi, setNewUpi] = useState("");
    const [qrFiles, setQrFiles] = useState([]);
    const [newOfflinePayment, setNewOfflinePayment] = useState({
        receiverName: "",
        receiverContact: "",
        label: "",
    });

    // Loading & progress state
    const [loading, setLoading] = useState(false);
    const [uploadProgress, setUploadProgress] = useState(0);

    // Fetch existing setup
    const fetchSetup = async () => {
        if (!managerId) return;
        try {
            const res = await axios.get(
                `/api/payments/setup/${managerId}/${tournamentId || ""}`
            );
            if (res.data.success) setExistingSetup(res.data.data);
            console.log(res.data)
        } catch (err) {
            console.error("Fetch setup error:", err);
        }
    };

    useEffect(() => {
        fetchSetup();
    }, [managerId, tournamentId]);

    const handleAddUpi = () => {
        if (!newUpi.trim()) return;
        setExistingSetup(prev => ({
            ...prev,
            upiIds: [...prev.upiIds, { _id: `temp-${Date.now()}`, upi: newUpi.trim() }],
        }));
        setNewUpi("");
    };

    const handleAddOfflinePayment = () => {
        if (!newOfflinePayment.receiverName.trim() || !newOfflinePayment.receiverContact.trim()) return;
        setExistingSetup(prev => ({
            ...prev,
            offlinePayments: [...prev.offlinePayments, { _id: `temp-${Date.now()}`, ...newOfflinePayment }],
        }));
        setNewOfflinePayment({ receiverName: "", receiverContact: "", label: "" });
    };

    const handleOfflinePaymentChange = (field, value) => {
        setNewOfflinePayment(prev => ({ ...prev, [field]: value }));
    };

    const handleFileChange = e => {
        const files = Array.from(e.target.files);
        setQrFiles(prev => [...prev, ...files]);
    };

    const handleSubmit = async () => {
        if (!managerId) return alert("Manager ID is required");

        try {
            const formData = new FormData();

            // Attach QR files
            qrFiles.forEach(file => formData.append("qrCodes", file));

            // Attach IDs
            formData.append("managerId", managerId);
            if (tournamentId) formData.append("tournamentId", tournamentId);

            // Prepare new entries
            const newUpis = existingSetup.upiIds.filter(u => u._id?.startsWith("temp-")).map(u => u.upi);
            const newOffline = existingSetup.offlinePayments.filter(o => o._id?.startsWith("temp-"));

            formData.append("upiIds", JSON.stringify(newUpis));
            formData.append("offlinePayments", JSON.stringify(newOffline));

            setLoading(true);
            setUploadProgress(0);

            const res = await axios.post(
                `/api/payments/setup`,
                formData,
                {
                    onUploadProgress: progressEvent => {
                        const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
                        setUploadProgress(percentCompleted);
                    },
                }
            );

            if (res.data.success) {
                alert("Payment setup saved!");
                setQrFiles([]);
                fetchSetup();
            } else {
                alert(res.data.message || "Failed to save payment setup");
            }
        } catch (err) {
            console.error("Error submitting payment setup:", err);
            alert("Error saving setup. Check console.");
        } finally {
            setLoading(false);
            setUploadProgress(0);
        }
    };

    const handleDelete = async (optionId, type) => {
        if (!managerId) return;
        try {
            await axios.delete(`/api/payments/setup/delete`, {
                data: { managerId, optionId, type },
            });

            setExistingSetup(prev => ({
                ...prev,
                qrCodes: prev.qrCodes.filter(q => q._id !== optionId),
                upiIds: prev.upiIds.filter(u => u._id !== optionId),
                offlinePayments: prev.offlinePayments.filter(o => o._id !== optionId),
            }));
        } catch (err) {
            console.error(err);
            alert("Error deleting option");
        }
    };

    return (
        <div className="p-6 bg-white shadow-md rounded-lg">
            <h2 className="text-xl font-bold mb-4">Payment Setup</h2>

            {/* Loading Spinner */}
            {loading && (
                <div className="mb-4 p-2 bg-blue-100 rounded">
                    Uploading... {uploadProgress}%
                </div>
            )}

            {/* QR Upload */}
            <div className="mt-4">
                <label className="block mb-2 font-medium">Upload QR Codes</label>
                <input type="file" multiple accept="image/*" onChange={handleFileChange} className="mb-4" />
                <div className="flex gap-2 flex-wrap">
                    {/* Newly selected files (preview only) */}
                    {qrFiles.map((file, i) => (
                        <div key={`new-${i}`} className="relative">
                            <img
                                src={URL.createObjectURL(file)}
                                alt="qr"
                                className="w-24 h-24 object-cover border rounded"
                            />
                            {/* Badge */}
                            <span className="absolute top-0 left-0 bg-yellow-400 text-xs px-1 rounded-bl">
                                Preview
                            </span>
                            <button
                                onClick={() => setQrFiles(qrFiles.filter((_, idx) => idx !== i))}
                                className="absolute top-0 right-0 bg-red-500 text-white text-xs px-1 rounded"
                            >
                                ✕
                            </button>
                        </div>
                    ))}

                    {/* Existing uploaded QR codes */}
                    {existingSetup.qrCodes?.map(qr => (
                        <div key={qr._id} className="relative">
                            <img
                                src={`/${qr.imageUrl}`}
                                alt="qr"
                                className="w-24 h-24 object-cover border rounded"
                            />
                            {/* Badge */}
                            <span className="absolute top-0 left-0 bg-green-500 text-xs px-1 rounded-bl text-white">
                                Uploaded
                            </span>
                            <button
                                onClick={() => handleDelete(qr._id, "qr")}
                                className="absolute top-0 right-0 bg-red-500 text-white text-xs px-1 rounded"
                            >
                                ✕
                            </button>
                        </div>
                    ))}
                </div>
            </div>

            {/* UPI IDs */}
            <div className="mt-4">
                <label className="block mb-2 font-medium">Add UPI IDs</label>
                <div className="flex gap-2">
                    <input type="text" value={newUpi} onChange={e => setNewUpi(e.target.value)}
                        className="border p-2 rounded w-full" placeholder="Enter UPI ID" />
                    <button onClick={handleAddUpi} className="px-4 py-2 bg-blue-500 text-white rounded">Add</button>
                </div>
                <ul className="mt-2 list-disc ml-6">
                    {existingSetup.upiIds?.map(u => (
                        <li key={u._id} className="flex items-center gap-2 mb-1">
                            <span>{u.upi}</span>
                            <button onClick={() => handleDelete(u._id, "upi")} className="text-red-500 text-sm">Delete</button>
                        </li>
                    ))}
                </ul>
            </div>

            {/* Offline Payments */}
            <div className="mt-6">
                <label className="block mb-2 font-medium">Add Offline Payment Receivers</label>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mb-2">
