                        onChange={e => handleOfflinePaymentChange("receiverName", e.target.value)}
                        className="border p-2 rounded" placeholder="Receiver Name" />
                    <input type="text" value={newOfflinePayment.receiverContact}
                        onChange={e => handleOfflinePaymentChange("receiverContact", e.target.value)}
                        className="border p-2 rounded" placeholder="Contact Number" />
                    <input type="text" value={newOfflinePayment.label}
                        onChange={e => handleOfflinePaymentChange("label", e.target.value)}
                        className="border p-2 rounded" placeholder="Label (optional)" />
                </div>
                <button onClick={handleAddOfflinePayment} className="px-4 py-2 bg-green-500 text-white rounded">Add Receiver</button>

                <div className="mt-3 space-y-2">
                    {existingSetup.offlinePayments?.map(o => (
                        <div key={o._id} className="bg-gray-50 p-3 rounded border flex justify-between items-center">
                            <div>
                                <div className="font-medium">{o.receiverName}</div>
                                <div className="text-sm text-gray-600">{o.receiverContact}</div>
                                {o.label && <div className="text-sm text-blue-600">{o.label}</div>}
                            </div>
                            <button onClick={() => handleDelete(o._id, "offline")}
                                className="text-red-500 text-sm px-2 py-1 border border-red-300 rounded">Delete</button>
                        </div>
                    ))}
                </div>
            </div>

            <button onClick={handleSubmit} disabled={loading} className={`mt-6 px-6 py-2 rounded shadow ${loading ? "bg-gray-400" : "bg-green-600 text-white"}`}>
                {loading ? `Saving (${uploadProgress}%)` : "Save Setup"}
            </button>
        </div>
    );
};

