            </SettingItem>
          </div>

          {/* Preferences */}
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-800 flex items-center">
              <Palette className="h-5 w-5 mr-2 text-blue-600" />
              Preferences
            </h2>

            <SettingItem
              icon={Globe}
              title="Language"
              subtitle="Choose your language"
            >
              <select
                value={settings.preferences.language}
                onChange={(e) => handleLanguageChange(e.target.value)}
                disabled={saving}
                className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:opacity-50"
              >
                <option value="English">English</option>
                <option value="Hindi">Hindi</option>
                <option value="Spanish">Spanish</option>
                <option value="French">French</option>
              </select>
            </SettingItem>

            <SettingItem
              icon={settings.preferences.theme === "light" ? Sun : Moon}
              title="App Theme"
              subtitle="Choose your preferred theme"
            >
              <div className="flex space-x-2">
                <button
                  onClick={() => handleThemeChange("light")}
                  disabled={saving}
                  className={`px-3 py-1 rounded-full text-sm font-medium transition-colors disabled:opacity-50 ${
                    settings.preferences.theme === "light"
                      ? "bg-blue-100 text-blue-700"
                      : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                  }`}
                >
                  Light
                </button>
                <button
                  onClick={() => handleThemeChange("dark")}
                  disabled={saving}
                  className={`px-3 py-1 rounded-full text-sm font-medium transition-colors disabled:opacity-50 ${
                    settings.preferences.theme === "dark"
                      ? "bg-blue-100 text-blue-700"
                      : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                  }`}
                >
                  Dark
                </button>
              </div>
            </SettingItem>
          </div>

          {/* Privacy */}
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-800 flex items-center">
              <Shield className="h-5 w-5 mr-2 text-blue-600" />
              Privacy & Security
            </h2>

            <SettingItem
              icon={Eye}
              title="Public Profile"
              subtitle="Show profile to other users"
            >
              <Toggle
                checked={settings.privacy.publicProfile}
                onChange={() => handlePrivacyChange("publicProfile")}
              />
            </SettingItem>

            <SettingItem
              icon={Phone}
              title="Share Contact Info"
              subtitle="Allow teams to see your contact"
            >
              <Toggle
                checked={settings.privacy.shareContact}
                onChange={() => handlePrivacyChange("shareContact")}
              />
            </SettingItem>
          </div>
        </div>

        {/* Support & About */}
        <div className="grid gap-6 md:grid-cols-2 mt-6">
          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-800 flex items-center">
              <HelpCircle className="h-5 w-5 mr-2 text-blue-600" />
              Support & Help
            </h2>

            <div className="bg-white rounded-lg border border-gray-200 p-4">
              <div className="flex gap-[20px]">
                <div className="flex items-center space-x-1">
                  <Phone className="h-4 w-4 text-gray-400" />
                  {appInfo.supportPhone ? (
                    <span className="text-sm text-gray-600">
                      {appInfo.supportPhone}
                    </span>
                  ) : (
                    <LoadingSkeleton />
                  )}
                </div>
                <div className="flex items-center space-x-1">
                  <Mail className="h-4 w-4 text-gray-400" />
                  {appInfo.supportEmail ? (
                    <span className="text-sm text-gray-600">
                      {appInfo.supportEmail}
                    </span>
                  ) : (
                    <LoadingSkeleton />
                  )}
                </div>
              </div>

              <div className="mt-3 border-gray-200">
                <div className="flex gap-[20px]">
                  <a
                    href="#"
                    className="block text-sm text-blue-600 hover:text-blue-800 transition-colors"
                  >
                    FAQs
                  </a>
                  <a
                    href="#"
                    className="block text-sm text-blue-600 hover:text-blue-800 transition-colors"
                  >
                    Terms & Conditions
                  </a>
                  <a
                    href="#"
                    className="block text-sm text-blue-600 hover:text-blue-800 transition-colors"
                  >
                    Privacy Policy
                  </a>
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <h2 className="text-lg font-semibold text-gray-800 flex items-center">
              <Info className="h-5 w-5 mr-2 text-blue-600" />
              About
            </h2>

            <div className="bg-white rounded-lg border border-gray-200 p-4">
              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <span className="text-sm text-gray-600">App Version</span>
                  {appInfo.version ? (
                    <span className="text-sm font-medium text-gray-900">
                      {appInfo.version}
                    </span>
                  ) : (
                    <div className="h-4 bg-gray-200 rounded w-16 animate-pulse"></div>
                  )}
                </div>
                {appInfo.description ? (
                  <p className="text-sm text-gray-600">{appInfo.description}</p>
                ) : (
                  <div className="space-y-2">
                    <div className="h-3 bg-gray-200 rounded animate-pulse"></div>
                    <div className="h-3 bg-gray-200 rounded w-3/4 animate-pulse"></div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>

        {/* Logout Button */}
        <div className="mt-8 flex justify-end">
          <button
            onClick={handleLogout}
            className="bg-red-50 hover:bg-red-100 text-red-700 font-medium py-3 px-4 rounded-lg border border-red-200 transition-colors duration-200 flex items-center justify-center space-x-2"
          >
            <LogOut className="h-5 w-5" />
            <span>Sign Out</span>
          </button>
        </div>

        {/* Password Change Modal */}
        {showPasswordModal && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
            <div className="bg-white rounded-xl shadow-xl max-w-md w-full p-6">
              <div className="flex items-center justify-between mb-4 border-b pb-2">
                <h3 className="text-lg font-semibold text-gray-900 whitespace-nowrap">
                  Change Password
                </h3>
                <button
                  onClick={() => {
                    setShowPasswordModal(false);
                    setPasswordError("");
                    setPasswordSuccess("");
                    setPasswordForm({
                      currentPassword: "",
                      newPassword: "",
                      confirmPassword: "",
                    });
                  }}
                  className="text-xl text-gray-400 hover:text-gray-600 focus:outline-none"
                  aria-label="Close modal"
                >
                  &times;
                </button>
              </div>

              <form onSubmit={handlePasswordChange} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Current Password
                  </label>
                  <input
                    type="password"
                    value={passwordForm.currentPassword}
                    onChange={(e) =>
                      setPasswordForm((prev) => ({
                        ...prev,
                        currentPassword: e.target.value,
                      }))
                    }
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    New Password
                  </label>
                  <input
                    type="password"
                    value={passwordForm.newPassword}
                    onChange={(e) =>
                      setPasswordForm((prev) => ({
                        ...prev,
                        newPassword: e.target.value,
                      }))
                    }
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                    minLength="6"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Confirm New Password
                  </label>
                  <input
                    type="password"
                    value={passwordForm.confirmPassword}
                    onChange={(e) =>
                      setPasswordForm((prev) => ({
                        ...prev,
                        confirmPassword: e.target.value,
                      }))
                    }
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                    required
                  />
                </div>

                {passwordError && (
                  <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg text-sm">
                    {passwordError}
                  </div>
                )}

                {passwordSuccess && (
                  <div className="bg-green-50 border border-green-200 text-green-700 px-4 py-3 rounded-lg text-sm">
                    {passwordSuccess}
                  </div>
                )}

                <div className="flex space-x-3 pt-4">
                  <button
                    type="button"
                    onClick={() => {
                      setShowPasswordModal(false);
                      setPasswordError("");
                      setPasswordSuccess("");
                      setPasswordForm({
                        currentPassword: "",
                        newPassword: "",
                        confirmPassword: "",
                      });
                    }}
                    className="flex-1 px-4 py-2 text-gray-700 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    disabled={saving}
                    className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
                  >
                    {saving ? (
                      <>
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                        Updating...
                      </>
                    ) : (
                      "Update Password"
                    )}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

