                      </td>

                      {/* Payment Status */}
                      <td className="px-6 py-4">
                        {updating === booking._id ? (
                          <div className="inline-flex items-center px-2 py-1 text-xs font-semibold rounded-full border bg-blue-50 text-blue-800 border-blue-200">
