                              className={`absolute right-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-gray-400 transition-transform duration-200 ${isOpen ? 'rotate-180' : ''}`}
                            />
                          </button>

                          {isOpen && (
                            <div className="absolute z-10 w-full mt-1 bg-white border border-gray-200 rounded-lg shadow-lg">
                              {categories.map((category) => (
                                <button
                                  key={category.value}
                                  onClick={() => {
                                    setselectedSuperPlayerCategory(category.label);
                                    setIsOpen(false);
                                  }}
                                  className={`w-full text-left px-4 py-3 hover:bg-gray-50 transition-colors duration-150 ${selectedSuperPlayerCategory === category.label ? 'bg-blue-50 text-blue-600' : 'text-gray-900'
                                    } ${category.value === categories[0].value ? 'rounded-t-lg' : ''} ${category.value === categories[categories.length - 1].value ? 'rounded-b-lg' : ''}`}
                                >
                                  <div className="flex items-center justify-between">
                                    <span>{category.label}</span>
                                    {selectedSuperPlayerCategory === category.label && (
                                      <Check className="w-4 h-4 text-blue-600" />
                                    )}
                                  </div>
                                </button>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                      <p>{selectedSuperPlayerCategory}</p>
                      <h2 className="text-lg font-semibold mb-3">
                        No Super Players
                      </h2>
                    </div>
                  </div>
                )}
              </div>
            </>
          )}
          {selectedTab === "Groups" && (
            <GroupsTab
              tournamentId={selectedTournament}
              activeSubGroupTab={activeSubGroupTab}
              setactiveSubGroupTab={setactiveSubGroupTab}
              activeGroup={activeGroup}
              setActiveGroup={setActiveGroup}
            />
          )}
        </div>
      )}
      <div>
        {modalStep === 1 && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
            <div className="bg-[#F0F4F9] p-[52px] rounded-[24px] relative min-w-[395px] shadow-lg min-h-[291px]">
              <button
                className="absolute top-0 right-6 text-xl text-gray-600 bg-transparent hover:bg-transparent w-0"
                onClick={closeModal}
              >
                <FiX />
              </button>
              <h2 className="text-[16px] md:text-[18px] font-[600] text-center text-black mb-[10px]">
                Create Number of Groups
              </h2>
              <p className="text-center text-[#333] md:text-[16px] font-[400]">
                Selected Players:{" "}
                <span className="font-[600] text-[#333] md:text-[16px]">
                  {selectedPlayers.length}
                </span>
              </p>
              <input
                type="number"
                placeholder="Enter number of groups"
                className="min-w-[291px] mt-[20px] mb-[20px] px-[24px] py-[8px] border rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500 min-h-[50px]"
                value={numGroups}
                onChange={(e) => {
                  if (e.target.value === "") {
                    setNumGroups("");
                    return;
                  }
                  const value = Math.max(
                    1,
                    parseInt(e.target.value) || 1
                  );
                  setNumGroups(value);
                }}
                min="1"
                required
              />
              <button
                className={`w-full py-3 rounded-full flex items-center justify-center gap-2 hover:bg-[#FF6A00] min-w-[291px] min-h-[48px] mt-0 ${numGroups && numGroups > 0
                  ? "bg-[#FF6600] text-white hover:bg-[#FF6A00]"
                  : "bg-gray-300 text-gray-500 cursor-not-allowed"
                  }`}
                onClick={handleNext}
                disabled={!numGroups || numGroups <= 0}
              >
                Next <FiArrowRight />
              </button>
            </div>
          </div>
        )}

        {modalStep === 2 && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
            <div className="bg-[#F0F4F9] p-[52px] rounded-[24px] relative w-[387px] shadow-lg max-h-[453px] min-w-[395px] overflow-y-auto">
              <button
                className="absolute top-0 right-6 text-xl text-gray-600 bg-transparent hover:bg-transparent w-0"
                onClick={closeModal}
              >
                <FiX />
              </button>
              <h2 className="font-[600] md:text-[18px] text-center text-black">
                Enter Group Names
              </h2>

              {groupNames.map((_, index) => (
                <div key={index} className="mt-[20px]">
                  <label className="block text-[#333] text-[14px] font-[500]">
                    Enter Group Name {index + 1}
                  </label>
                  <input
                    type="text"
                    className="min-w-[291px] min-h-[50px] px-[24px] py-[8px] border rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    placeholder={`Group ${index + 1}`}
                    value={groupNames[index]}
                    onChange={(e) => {
                      const value = e.target.value.replace(
                        /[^a-zA-Z\s-]/g,
                        ""
                      );
                      const newGroupNames = [...groupNames];
                      newGroupNames[index] = value;
                      setGroupNames(newGroupNames);
                    }}
                    required
                  />
                  {!groupNames[index] && (
                    <p className="text-red-500 text-xs mt-1">
                      Group name is required
                    </p>
                  )}
                </div>
              ))}

              <div className="flex justify-between mt-[20px] grpbtns">
                <button
                  className="rounded-full flex items-center justify-center gap-2 bg-gray-300 text-gray-800 mt-[0] backbtn hover:bg-transparent min-h-[48px] min-w-[133px]"
                  onClick={handleBack}
                >
                  <FiArrowLeft /> Back
                </button>
                <button
                  className={`flex items-center justify-center min-h-[48px] min-w-[133px] mt-0  rounded-full gap-2 nextbtns ${groupNames.every((name) => name.trim())
                    ? "bg-[#FF6600] text-white"
                    : "bg-gray-300 text-gray-500 cursor-not-allowed"
                    }`}
                  onClick={() => {
                    if (
                      groupNames.every((name) =>
                        name.trim()
                      )
                    ) {
                      const players = {};
                      groupNames.forEach((name) => {
                        players[name] = "";
                      });
                      setGroupPlayers(players);
                      handleNext();
                    }
                  }}
                  disabled={
                    !groupNames.every((name) => name.trim())
                  }
                >
                  Next <FiArrowRight />
                </button>
              </div>
            </div>
          </div>
        )}

        {modalStep === 3 && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
            <div className="bg-[#F0F4F9] p-[52px] rounded-[24px] relative min-w-[395px] max-h-[515px] shadow-lg overflow-y-auto">
              <button
                className="absolute top-0 right-6 text-xl text-gray-600 bg-transparent hover:bg-transparent w-0"
                onClick={closeModal}
              >
                <FiX />
              </button>
              <h2 className="md:text-[18px] font-[600] text-center text-gray-800 mb-[10px]">
                Create Number of Groups
              </h2>
              <p className="text-[#333] text-[16px] font-[400] text-center mb-[10px]">
                Selected Players:
                <span className="text-black font-[500]">
                  {" "}
                  {selectedPlayers.length}
                </span>
              </p>
              <p className="text-[#333] text-center text-[16px]">
                Enter number of players for each group
              </p>

              {groupNames.map((groupName, index) => (
                <div key={index} className="mt-[10px]">
                  <label className="block text-black text-[14px] font-[500]">
                    {groupName}
                  </label>
                  <input
                    type="number"
                    placeholder="Enter number of players"
                    className="min-w-[291px] min-h-[50px] px-[24px] py-[8px] border rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-blue-500"
                    value={groupPlayers[groupName] || ""}
                    onChange={(e) => {
                      if (e.target.value === "") {
                        setGroupPlayers({
                          ...groupPlayers,
                          [groupName]: "",
                        });
                        return;
                      }
                      const value = Math.max(
                        0,
                        parseInt(e.target.value) || 0
                      );
                      setGroupPlayers({
                        ...groupPlayers,
                        [groupName]: value,
                      });
                    }}
                    min="0"
                    max={selectedPlayers.length}
                    required
                  />
                  {groupPlayers[groupName] === "" && (
                    <p className="text-red-500 text-xs mt-1">
                      Number of players is required
                    </p>
                  )}
                </div>
              ))}

              <div className="flex justify-between mt-6 grpbtns">
                <button
                  className="px-4 py-2 flex items-center justify-center gap-2 rounded-full bg-gray-300 text-gray-800 backbtn hover:bg-transparent min-h-[48px] min-w-[133px]"
                  onClick={handleBack}
                >
                  <FiArrowLeft /> Back
                </button>
                <button
                  className={`px-4 py-2 rounded-full flex items-center justify-center gap-2 min-h-[48px] min-w-[133px] nextbtns ${groupNames.every(
                    (name) =>
                      groupPlayers[name] !== "" &&
                      !isNaN(groupPlayers[name])
                  ) &&
                    groupNames.reduce(
                      (sum, name) =>
                        sum +
                        (parseInt(groupPlayers[name]) || 0),
                      0
                    ) <= selectedPlayers.length
                    ? "bg-[#FF6600] text-white hover:bg-[#004E93]"
                    : "bg-gray-300 text-gray-500 cursor-not-allowed"
                    }`}
                  onClick={handleNext}
                  disabled={
                    !groupNames.every(
                      (name) =>
                        groupPlayers[name] !== "" &&
                        !isNaN(groupPlayers[name])
                    ) ||
                    groupNames.reduce(
                      (sum, name) =>
                        sum +
                        (parseInt(groupPlayers[name]) || 0),
                      0
                    ) > selectedPlayers.length
                  }
                >
                  Next <FiArrowRight />
                </button>
              </div>
            </div>
          </div>
        )}

        {modalStep === 4 && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
            <div className="bg-[#F0F4F9] p-[52px] rounded-[24px] relative min-w-[381px] min-h-[294px] shadow-lg">
              <button
                className="absolute top-0 right-6 text-xl text-gray-600 bg-transparent hover:bg-transparent w-0"
                onClick={closeModal}
              >
                <FiX />
              </button>
              <h2 className="md:text-[18px] text-[#333] font-[600] text-center mb-2">
                Confirm Group Creation
              </h2>
              <p className="md:text-[16px] font-[400] mt-[10px] text-center text-[#333] mb-[10px]">
                Distribution of Players
              </p>

              {groupNames.map((groupName) => (
                <p
                  key={groupName}
                  className="text-center text-gray-800 font-semibold mt-[10px]"
                >
                  Group {groupName}:{" "}
                  {groupPlayers[groupName] || 0} Players
                </p>
              ))}

              <div className="flex justify-between mt-[20px] cancelbtn">
                <button
                  className="px-4 py-2 flex items-center justify-center gap-2 rounded-full bg-gray-300 text-gray-800 backbtn hover:bg-transparent min-h-[48px] min-w-[133px] mt-0"
                  onClick={handleBack}
                >
                  <FiArrowLeft /> Back
                </button>
                <button
                  className="rounded-full bg-[#FF6600] text-white flex createbtn gap-[8px] justify-center items-center hover:bg-[#FF6600] min-h-[48px] min-w-[133px] mt-0"
                  onClick={handleCreateGroup}
                >
                  <FiPlus /> Create
                </button>
              </div>
            </div>
          </div>
        )}

        {modalStep === 5 && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50">
            <div className="bg-[#F0F4F9] p-[52px] rounded-2xl relative min-w-[404px] min-h-[265px] shadow-lg">
              <button
                className="absolute top-0 right-6 text-xl text-gray-600 bg-transparent hover:bg-transparent w-0"
                onClick={closeModal}
              >
                <FiX />
              </button>
              <h2 className="text-lg font-semibold text-center text-gray-800">
                Created {numGroups} Groups Successfully
              </h2>

              {groupNames.map((groupName) => (
                <p
                  key={groupName}
                  className="text-center text-gray-800 font-semibold mt-2"
                >
                  {groupName}:{" "}
                  {groupPlayers[groupName] || 0} Players
                </p>
              ))}

              <div className="flex justify-between mt-6 cancelbtn">
                <button
                  className="px-[24px] py-[14px] rounded-full viewbtn text-[#333] hover:bg-transparent min-h-[48px] min-w-[138px]"
                  onClick={handleViewGroups}
                >
                  View Groups
                </button>
                <button
                  className="px-4 py-2 rounded-full bg-[#FF6600] text-white min-h-[48px] min-w-[138px]"
                  onClick={closeModal}
                >
                  OK
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default TournamentManagement;

// TournamentList.js
import { useState, useEffect } from "react";
import axios from "axios";
import { FiEdit2, FiTrash2, FiShare2, FiX } from "react-icons/fi";
import { useNavigate } from "react-router-dom";

const TournamentList = ({ onTournamentSelect, selectedTournament }) => {
  const [tournaments, setTournaments] = useState([]);
  const [activeTab, setActiveTab] = useState("Live"); // Live, Upcoming, Recent
  const [displayData, setDisplayData] = useState([]);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingTournament, setEditingTournament] = useState(null);
  const [editFormData, setEditFormData] = useState({});
  const [editImage, setEditImage] = useState(null);
  const [editImageFile, setEditImageFile] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth <= 768);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  useEffect(() => {
    axios
      .get(`/api/tournaments`)
      .then((response) => {
        setTournaments(response.data);
      })
      .catch((error) => {
        console.error("Error fetching tournaments:", error);
      });
  }, []);

  useEffect(() => {
    if (tournaments.length > 0 && !selectedTournament) {
      // Set the first tournament as selected by default
      onTournamentSelect(tournaments[0]._id);
    }
  }, [tournaments, selectedTournament, onTournamentSelect]);

  useEffect(() => {
    if (activeTab === "Live") {
      setDisplayData(tournaments);
    } else {
      setDisplayData([]);
    }
  }, [activeTab, tournaments]);

  const handleDelete = async (id) => {
    try {
      await axios.delete(`/api/tournaments/${id}`);
      setTournaments(tournaments.filter((tournament) => tournament._id !== id));
    } catch (error) {
      console.error("Error deleting tournament:", error);
      alert("Failed to delete tournament");
    }
  };

  const handleEditClick = async (tournamentId, e) => {
    e.stopPropagation();

    try {
      const response = await axios.get(`/api/tournaments/${tournamentId}`);
      const tournamentData = response.data.tournament;

      // Prepare form data for editing
      const formData = {
        title: tournamentData.title || "",
        type: tournamentData.type || "group stage",
        sportsType: tournamentData.sportsType || "",
        description: tournamentData.description || "",
        organizerName: tournamentData.organizerName || "",
        cancellationPolicy: tournamentData.cancellationPolicy || "NO",
        eventLocation: Array.isArray(tournamentData.eventLocation)
          ? tournamentData.eventLocation.join(", ")
          : tournamentData.eventLocation || "",
        startDate: tournamentData.startDate || "",
        endDate: tournamentData.endDate || "",
        termsAndConditions: tournamentData.termsAndConditions || "",
        playFormat: tournamentData.playFormat || "Singles",
        category: tournamentData.category || [{ name: "Open Category", fee: 0 }],
        selectedTime: tournamentData.selectedTime || { startTime: "10:00", endTime: "18:00" }
      };

      setEditFormData(formData);
      setEditingTournament(tournamentData);

      // Set existing logo if available
      if (tournamentData.tournamentLogo) {
        setEditImage(`/uploads/${tournamentData.tournamentLogo}`);
      }

      setShowEditModal(true);
    } catch (error) {
      console.error("Error fetching tournament details:", error);
      alert("Failed to load tournament details");
    }
  };

  const handleEditInputChange = (e) => {
    const { name, value } = e.target;
    setEditFormData({
      ...editFormData,
      [name]: value,
    });
  };

  const handleCategoryChange = (index, field, value) => {
    const updatedCategories = [...editFormData.category];
    updatedCategories[index][field] = field === "fee" ? Math.max(0, Number(value)) : value;
    setEditFormData({ ...editFormData, category: updatedCategories });
  };

  const addCategory = () => {
    setEditFormData({
      ...editFormData,
      category: [...editFormData.category, { name: "", fee: 0 }],
    });
  };

  const handleTimeChange = (field, value) => {
    setEditFormData({
      ...editFormData,
      selectedTime: {
        ...editFormData.selectedTime,
        [field]: value,
      },
    });
  };

  const handleEditImageChange = (event) => {
    const file = event.target.files[0];
    if (file) {
      setEditImageFile(file); // Store the file for submission
      setEditImage(URL.createObjectURL(file)); // Create preview URL
    }
  };

  const handleEditSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError("");

    try {
      if (!editFormData.title || !editFormData.type || !editFormData.sportsType) {
        setError("Title, Type, and Sports Type are required");
        setIsSubmitting(false);
        return;
      }

      const tournamentFormData = new FormData();

      // Logo
      if (editImageFile) {
        tournamentFormData.append("tournamentLogo", editImageFile);
      }

      // Basic fields
      tournamentFormData.append("title", editFormData.title.trim());
      tournamentFormData.append("type", editFormData.type.toLowerCase());
      tournamentFormData.append("sportsType", editFormData.sportsType);
      tournamentFormData.append("description", editFormData.description || "");
      tournamentFormData.append("organizerName", editFormData.organizerName || "");
      tournamentFormData.append("cancellationPolicy", editFormData.cancellationPolicy || "NO");
      tournamentFormData.append("termsAndConditions", editFormData.termsAndConditions || "");

      // Play format (only for knockout tournaments)
      if (editFormData.type === "knockout") {
        tournamentFormData.append("playFormat", editFormData.playFormat || "Singles");
      }

      // Dates
      if (editFormData.startDate)
        tournamentFormData.append("startDate", editFormData.startDate);
      if (editFormData.endDate)
        tournamentFormData.append("endDate", editFormData.endDate);

      // Selected time
      if (editFormData.selectedTime) {
        tournamentFormData.append("selectedTime", JSON.stringify(editFormData.selectedTime));
      }

      // Category
      if (editFormData.category && Array.isArray(editFormData.category)) {
        tournamentFormData.append("category", JSON.stringify(editFormData.category));
      }

      // Event Location
      if (editFormData.eventLocation) {
        tournamentFormData.append("eventLocation", editFormData.eventLocation);
      }

      const response = await axios.put(
        `/api/tournaments/edit/${editingTournament._id}`,
        tournamentFormData,
        {
          headers: {
            "Content-Type": "multipart/form-data",
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      // Update the tournament in the list
      const updatedTournaments = tournaments.map(tournament =>
        tournament._id === editingTournament._id
          ? { ...tournament, ...response.data.tournament }
          : tournament
      );
      setTournaments(updatedTournaments);

      setShowEditModal(false);
      setEditImage(null);
      setEditImageFile(null);
      alert("Tournament updated successfully!");
    } catch (error) {
      console.error("Error updating tournament:", error);
      setError(error.response?.data?.message || "Failed to update tournament");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleShareClick = (tournament, e) => {
    e.stopPropagation();

    // Create shareable link
    const shareLink = `${window.location.origin}/tournament/${tournament._id}`;

    // Copy to clipboard
    navigator.clipboard.writeText(shareLink)
      .then(() => {
        alert(`Tournament link copied to clipboard!\n\n${shareLink}`);
      })
      .catch(err => {
        console.error('Failed to copy: ', err);
        // Fallback: show alert with link
        alert(`Share this tournament link:\n\n${shareLink}`);
      });
  };

  return (
    <div className="rounded-lg p-4 mb-4">
      <h5 className="mb-3 text-lg font-semibold">Tournament List</h5>

      <div className="flex mb-4 bg-white rounded-full w-fit p-1">
        {["Live", "Upcoming", "Recent"].map((tab, index) => (
          <button
            key={index}
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-2 rounded-full text-sm font-semibold transition flex items-center gap-2 ${activeTab === tab
              ? "bg-[#004E93] text-white shadow-md"
              : "bg-transparent text-gray-600"
              }`}
          >
            {tab}
            <span
              className={`text-xs font-semibold px-2 py-1 rounded-full min-w-[31px] text-center ${activeTab === tab
                ? "bg-orange-500 text-white"
                : "bg-[#E6E5E8] text-gray-600"
                }`}
            >
              {index === 0 ? tournaments.length : index === 1 ? "0" : "0"}
            </span>
          </button>
        ))}
      </div>

      <div className="space-y-3">
        {displayData.length > 0 ? (
          displayData.map((tournament) => (
            <div
              key={tournament._id}
              className={`flex justify-between items-center p-4 rounded-lg cursor-pointer transition-colors duration-300 ${selectedTournament === tournament._id
                ? "bg-[#004E93] text-white"
                : "bg-white"
                }`}
              onClick={() => {
                onTournamentSelect(tournament._id);

                if (tournament.type?.toLowerCase() === "knockout") {
                  navigate(`/tournament-management/team-knockouts?tournamentId=${tournament._id}`);
                } else if (tournament.type?.toLowerCase() === "group stage") {
                  navigate(`/tournament-management/group-stage?tournamentId=${tournament._id}`);
                } else {
                  onTournamentSelect(tournament._id);
                }
              }}
            >
              <div className="flex items-center gap-3 flex-1 min-w-0">
                <div className="w-12 h-12 flex items-center justify-center bg-gray-200 rounded-full flex-shrink-0">
                  🏆
                </div>
                <div className="min-w-0 flex-1">
                  <h3 className={`text-lg font-medium truncate ${selectedTournament === tournament._id ? "text-white" : "text-gray-800"
                    }`}>
                    {tournament.title}
                  </h3>
                  <p className={`text-sm ${selectedTournament === tournament._id ? "text-gray-100" : "text-gray-600"
                    }`}>
                    {tournament.type}
                  </p>
                </div>
              </div>

              <div className="flex gap-3 ml-2">
                <FiEdit2
                  className="text-lg cursor-pointer hover:text-blue-500"
                  onClick={(e) => handleEditClick(tournament._id, e)}
                />
                <FiTrash2
                  className="text-lg cursor-pointer hover:text-red-500"
                  onClick={(e) => {
                    e.stopPropagation();
                    if (window.confirm("Are you sure you want to delete this tournament?")) {
                      handleDelete(tournament._id);
                    }
                  }}
                />
                <FiShare2
                  className="text-lg cursor-pointer hover:text-green-500"
                  onClick={(e) => handleShareClick(tournament, e)}
                />
              </div>
            </div>
          ))
        ) : (
          <div className="flex items-center justify-center p-6 bg-white rounded-lg">
            <div className="text-center">
              <p className="text-lg font-medium text-gray-600">
                No data found
              </p>
              <p className="text-sm text-gray-500 mt-1">
                {activeTab === "Upcoming"
                  ? "There are no upcoming tournaments scheduled."
                  : "There are no recent tournaments available."}
              </p>
            </div>
          </div>
        )}
      </div>

      {/* Edit Tournament Modal */}
      {showEditModal && editingTournament && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center z-50 p-4">
          <div className="bg-[#F2F4F6] p-6 rounded-lg shadow-lg w-full max-w-[1400px] md:w-[95vw] max-h-[80vh] overflow-y-auto relative">
            <button
              onClick={() => {
                setShowEditModal(false);
                setEditImage(null);
                setEditImageFile(null);
              }}
              className="absolute top-1 right-3 text-gray-500 hover:text-gray-700 bg-transparent w-0 hover:bg-transparent"
            >
              <FiX size={24} />
            </button>

            <h2 className="md:text-[24px] font-[500] mb-[24px] text-left">
              Edit Tournament
            </h2>

            {error && (
              <div className="bg-red-100 text-red-700 p-3 rounded-lg mb-4">
                {error}
              </div>
            )}

            <form onSubmit={handleEditSubmit}>
              {/* Upload Logo */}
              <div className="flex flex-col md:flex-row gap-[24px] rounded-lg mx-auto">
                <div className="w-full md:w-1/2">
                  <p className="md:text-[16px] font-[500] text-black mb-2">
                    Tournament Logo
                  </p>
                  <div className="w-full h-[240px] bg-gray-300 rounded-lg flex items-center justify-center relative">
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleEditImageChange}
                      className="absolute inset-0 opacity-0 cursor-pointer rounded-[16px]"
                    />
                    {editImage ? (
                      <img
                        src={editImage}
                        alt="Tournament Logo"
                        className="w-full h-full object-cover rounded-lg"
                      />
                    ) : (
                      <span className="text-gray-500 text-4xl">📷</span>
                    )}
                  </div>
                </div>

                <div className="w-full md:w-1/2 self-end">
                  <p className="text-sm text-gray-600 mb-2">
                    {editImage ? "Click to change logo" : "Click to upload logo"}
                  </p>
                </div>
              </div>

              {/* Form Fields */}
              <div className="mx-auto mt-5 rounded-lg">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-[24px]">
                  {/* Left Column */}
                  <div>
                    {/* Title */}
                    <label className="font-[500]">Tournament Name</label>
                    <input
                      type="text"
                      name="title"
                      value={editFormData.title}
                      onChange={handleEditInputChange}
                      className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[50px]"
                      placeholder="Enter name"
                      required
                    />

                    {/* Type */}
                    <label className="font-[500]">Tournament Type</label>
                    <select
                      name="type"
                      value={editFormData.type}
                      onChange={handleEditInputChange}
                      className="w-full mb-5 p-2 border rounded-[8px] h-[50px]"
                    >
                      <option value="group stage">Group Stage</option>
                      <option value="knockout">Knockout</option>
                    </select>

                    {editFormData.type === "knockout" && (
                      <>
                        <label className="font-[500]">Play Format</label>
                        <select
                          name="playFormat"
                          value={editFormData.playFormat}
                          onChange={handleEditInputChange}
                          className="w-full mb-5 p-2 border rounded-[8px] h-[50px]"
                        >
                          <option value="Singles">Singles</option>
                          <option value="Doubles">Doubles</option>
                        </select>
                      </>
                    )}

                    {/* Sports */}
                    <label className="font-[500]">Sports Type</label>
                    <input
                      type="text"
                      name="sportsType"
                      value={editFormData.sportsType}
                      onChange={handleEditInputChange}
                      className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[50px]"
                      placeholder="e.g. Tennis, Football"
                      required
                    />

                    {/* Description */}
                    <label className="font-[500]">Event Description</label>
                    <textarea
                      name="description"
                      value={editFormData.description}
                      onChange={handleEditInputChange}
                      className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[100px]"
                    ></textarea>

                    {/* Location */}
                    <div className="mt-4">
                      <label className="font-[500]">Event Location</label>
                      <input
                        type="text"
                        name="eventLocation"
                        value={editFormData.eventLocation}
                        onChange={handleEditInputChange}
                        placeholder="Enter event location"
                        className="w-full p-2 border mb-5 rounded-[8px] h-[50px]"
                        required
                      />
                    </div>

                    {/* Cancellation Policy */}
                    <label className="font-[500]">Cancellation Policy</label>
                    <select
                      name="cancellationPolicy"
                      value={editFormData.cancellationPolicy}
                      onChange={handleEditInputChange}
                      className="w-full p-2 mb-5 border rounded-[8px] mt-2 h-[50px]"
                    >
                      <option value="YES">YES</option>
                      <option value="NO">NO</option>
                    </select>
                  </div>

                  {/* Right Column */}
                  <div>
                    {/* Organizer */}
                    <label className="font-[500]">Organizer Name</label>
                    <input
                      type="text"
                      name="organizerName"
                      value={editFormData.organizerName}
                      onChange={handleEditInputChange}
                      className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[50px]"
                    />

                    {/* Category */}
                    <label className="font-[500]">
                      Categories (Name & Fee)
                    </label>
                    {editFormData.category?.map((cat, idx) => (
                      <div key={idx} className="flex gap-2 mb-2 items-center">
                        <input
                          type="text"
                          required
                          value={cat.name}
                          onChange={(e) =>
                            handleCategoryChange(idx, "name", e.target.value)
                          }
                          className="w-2/3 p-2 border rounded"
                          placeholder="Category name"
                        />
                        <input
                          type="number"
                          min="0"
                          required
                          value={cat.fee}
                          onChange={(e) =>
                            handleCategoryChange(idx, "fee", e.target.value)
                          }
                          className="w-1/3 p-2 border rounded"
                          placeholder="Fee"
                        />
                        {editFormData.category.length > 1 && (
                          <button
                            type="button"
                            onClick={() => {
                              const updatedCategories = editFormData.category.filter(
                                (_, i) => i !== idx
                              );
                              setEditFormData({
                                ...editFormData,
                                category: updatedCategories,
                              });
                            }}
                            className="p-2 text-red-500 hover:text-red-700 bg-transparent hover:bg-red-50 rounded"
                            title="Remove category"
                          >
                            <FiTrash2 size={18} />
                          </button>
                        )}
                      </div>
                    ))}
                    <button
                      type="button"
                      onClick={addCategory}
                      className="px-3 py-1 bg-blue-500 text-white rounded text-sm"
                    >
                      + Add Category
                    </button>

                    {/* Dates */}
                    <div className="mt-4">
                      <label className="font-[500]">Start Date</label>
                      <input
                        type="date"
                        name="startDate"
                        required
                        value={editFormData.startDate}
                        onChange={handleEditInputChange}
                        className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[50px]"
                      />

                      <label className="font-[500]">End Date</label>
                      <input
                        type="date"
                        name="endDate"
                        required
                        min={
                          editFormData.startDate ||
                          new Date().toISOString().split("T")[0]
                        }
                        value={editFormData.endDate}
                        onChange={handleEditInputChange}
                        className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[50px]"
                      />
                    </div>

                    {/* Select Time */}
                    <div className="mt-4">
                      <p className="text-sm font-medium mb-1">
                        Match Start & End Time
                      </p>
                      <div className="flex gap-[12px] bg-white p-4 w-[320px] rounded-[8px]">
                        <input
                          type="time"
                          name="startTime"
                          required
                          value={editFormData.selectedTime?.startTime || ""}
                          onChange={(e) => handleTimeChange("startTime", e.target.value)}
                          className="w-1/2 border rounded p-2"
                        />
                        <input
                          type="time"
                          name="endTime"
                          required
                          value={editFormData.selectedTime?.endTime || ""}
                          onChange={(e) => handleTimeChange("endTime", e.target.value)}
                          className="w-1/2 border rounded p-2"
                        />
                      </div>
                    </div>

                    {/* Terms */}
                    <label className="font-[500] mt-4">Terms & Conditions</label>
                    <textarea
                      name="termsAndConditions"
                      value={editFormData.termsAndConditions}
                      onChange={handleEditInputChange}
                      className="w-full p-2 border mb-5 rounded-[8px] mt-2 h-[100px]"
                    ></textarea>
                  </div>
                </div>
              </div>

              {/* Submit */}
              <button
                type="submit"
                disabled={isSubmitting}
                className="flex items-center gap-2 text-white font-semibold w-auto rounded-full transition bg-[#FF5B04] hover:bg-[#FF5B04] mt-6 ml-auto px-6 py-3"
                style={{ border: "1px solid #FF6A00" }}
              >
                {isSubmitting ? "Updating..." : "Update Tournament"}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

