import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../context/AuthContext";

const MTrainerApplications = () => {
  const { auth } = useContext(AuthContext);
  const [applications, setApplications] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("pending");

  useEffect(() => {
    if (auth?._id) {
      fetchApplications();
    }
  }, [filter, auth]);

  const fetchApplications = async () => {
    try {
      setLoading(true);
      const managerId = auth?._id;

      if (!managerId) {
        console.error("No manager ID found in auth context");
        return;
      }

      console.log(
        "Fetching applications for manager:",
        managerId,
        "with status:",
        filter
      );

      const response = await fetch(
        `/api/manager/trainer-applications?managerId=${managerId}&status=${filter}`
      );

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const data = await response.json();
      console.log("Fetched applications:", data);
      console.log("First application data:", data[0]);
      setApplications(data);
    } catch (error) {
      console.error("Error fetching applications:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleApplicationAction = async (
    applicationId,
    action,
    rejectionReason = ""
  ) => {
    try {
      const response = await fetch(
        `/api/manager/trainer-applications/${applicationId}/${action}`,
        {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
            "manager-id": auth?._id,
          },
          body: JSON.stringify({ rejectionReason }),
        }
      );

      if (response.ok) {
        fetchApplications(); // Refresh the list
      } else {
        const errorData = await response.json();
        console.error("Error response:", errorData);
        alert(errorData.message || "Failed to process application");
      }
    } catch (error) {
      console.error(`Error ${action} application:`, error);
      alert("Network error occurred");
    }
  };

  const getStatusBadge = (status) => {
    const statusStyles = {
      pending: "bg-yellow-100 text-yellow-800",
      approved: "bg-green-100 text-green-800",
      rejected: "bg-red-100 text-red-800",
    };

    const safeStatus = status || "pending";

    return (
      <span
        className={`px-2 py-1 rounded-full text-xs font-medium ${
          statusStyles[safeStatus] || statusStyles.pending
        }`}
      >
        {safeStatus.charAt(0).toUpperCase() + safeStatus.slice(1)}
      </span>
    );
  };

  // Add auth check
  if (!auth?._id) {
    return (
      <div className="flex justify-center items-center min-h-screen">
        <p className="text-gray-500">
          Please log in as a manager to view applications.
        </p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500"></div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-gray-900">
          Trainer Applications
        </h1>

        {/* Filter Buttons */}
        <div className="flex space-x-2">
          {["pending", "approved", "rejected"].map((status) => (
            <button
              key={status}
              onClick={() => setFilter(status)}
              className={`px-4 py-2 rounded-md text-sm font-medium transition-colors ${
                filter === status
                  ? "bg-orange-500 text-white"
                  : "bg-gray-200 text-gray-700 hover:bg-gray-300"
              }`}
            >
              {status.charAt(0).toUpperCase() + status.slice(1)}
            </button>
          ))}
        </div>
      </div>

      {/* Applications List */}
      <div className="space-y-4">
        {applications.length === 0 ? (
          <div className="bg-white rounded-lg shadow p-8 text-center">
            <p className="text-gray-500">No {filter} applications found.</p>
          </div>
        ) : (
          applications.map((application) => (
            <div
              key={application._id}
              className="bg-white rounded-lg shadow hover:shadow-lg transition-shadow"
            >
              {/* Card Header */}
              <div className="p-6 border-b border-gray-200">
                <div className="flex justify-between items-start">
                  <div className="space-y-2">
                    <h3 className="text-lg font-semibold text-gray-900 flex items-center">
                      <svg
                        className="w-5 h-5 text-orange-500 mr-2"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"
                        />
                      </svg>
                      Trainer Application
                    </h3>
                    <div className="flex items-center space-x-4 text-sm text-gray-600">
                      <div className="flex items-center">
                        <svg
                          className="w-4 h-4 mr-1"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z"
                          />
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M15 11a3 3 0 11-6 0 3 3 0 016 0z"
                          />
                        </svg>
                        {application.clubName || "Unknown Club"} -{" "}
                        {application.turfName || "Unknown Turf"}
                      </div>
                      <div className="flex items-center">
                        <svg
                          className="w-4 h-4 mr-1"
                          fill="none"
                          stroke="currentColor"
                          viewBox="0 0 24 24"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth={2}
                            d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"
                          />
                        </svg>
                        {new Date(application.appliedAt).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                  {getStatusBadge(
                    application.managerStatus ||
                      application.overallStatus ||
                      "pending"
                  )}
                </div>
              </div>

              {/* Card Content */}
              <div className="p-6 space-y-4">
                {/* Trainer Info */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <h4 className="font-semibold text-gray-900 mb-2">
                      Trainer Information
                    </h4>
                    <div className="space-y-1 text-sm">
                      <p>
                        <span className="font-medium">Trainer:</span>{" "}
                        {application.trainerId?.name || "Unknown Trainer"}
                      </p>
                      <p>
                        <span className="font-medium">Trainer ID:</span>{" "}
                        {application.trainerId?._id ||
                          application.trainerId ||
                          "Unknown"}
                      </p>
                      {application.trainerSports && (
                        <p>
                          <span className="font-medium">Sports:</span>{" "}
                          {Array.isArray(application.trainerSports)
                            ? application.trainerSports.join(", ")
                            : application.trainerSports}
