                    >
                      <svg
                        className="w-4 h-4 mr-1"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"
                        />
                      </svg>
                      Approve
                    </button>
                    <button
                      onClick={() => {
                        const reason = prompt(
                          "Enter rejection reason (optional):"
                        );
                        handleApplicationAction(
                          application._id,
                          "reject",
                          reason
                        );
                      }}
                      className="flex items-center px-4 py-2 border border-red-300 text-red-600 hover:bg-red-50 rounded-md text-sm font-medium transition-colors w-auto bg-transparent"
                    >
                      <svg
                        className="w-4 h-4 mr-1"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth={2}
                          d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z"
                        />
                      </svg>
                      Reject
                    </button>
                  </div>
                )}

                {/* Rejection Reason */}
                {(application.managerStatus === "rejected" ||
                  application.overallStatus === "rejected") &&
                  application.managerRejectionReason && (
                    <div className="bg-red-50 p-3 rounded border border-red-200">
                      <h4 className="font-semibold text-red-800 mb-1">
                        Rejection Reason:
                      </h4>
                      <p className="text-sm text-red-700">
                        {application.managerRejectionReason}
                      </p>
                    </div>
                  )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

