import React, { useState, useEffect } from "react";
import axios from "axios";

const NotificationPage = () => {
  const [activeTab, setActiveTab] = useState("All");
  const [paymentFilter, setPaymentFilter] = useState("Online");
  const [notifications, setNotifications] = useState([]);
  const [selected, setSelected] = useState([]);
  const [loading, setLoading] = useState(false);

  // State to track tournament statuses
  const [tournamentStatusMap, setTournamentStatusMap] = useState({});

  // State to track active tournaments for tabs
  const [activeTournaments, setActiveTournaments] = useState([]);

  // State to track payment method within tournament tabs
  const [tournamentPaymentFilter, setTournamentPaymentFilter] = useState({});

  // State for currently selected tournament in tournament tabs
  const [currentTournamentTab, setCurrentTournamentTab] = useState(null);

  useEffect(() => {
    const fetchNotifications = async () => {
      const user = localStorage.getItem("user");
      if (!user) return;

      const manager = JSON.parse(user);
      if (!manager?._id) return;

      try {
        const res = await axios.get(
          `/api/payments/${manager._id}/notifications`
        );
        if (res.data.success) {
          const mapped = res.data.notifications.map((n) => ({
            ...n,
            type: "payment",
            status: n.transactionStatus,
            paymentMethod: n.paymentMethod,
            user: n.userId,
          }));
          setNotifications(mapped);

          // Fetch tournament statuses to categorize notifications
          await fetchTournamentStatuses(mapped);
        }
      } catch (err) {
        console.error("Failed to fetch notifications:", err);
      }
    };

    const fetchTournamentStatuses = async (notificationsList) => {
      try {
        // Get unique tournament IDs from notifications
        const tournamentIds = [...new Set(notificationsList.map(n => n.tournamentId))];

        // Fetch each tournament to determine its status
        const statusMap = {};
        const activeTournamentsList = [];

        for (const tournamentId of tournamentIds) {
          try {
            const tournamentRes = await axios.get(`/api/tournaments/${tournamentId}`);
            if (tournamentRes.data.success && tournamentRes.data.tournament) {
              const tournament = tournamentRes.data.tournament;
              const now = new Date();
              const endDate = tournament.endDate ? new Date(tournament.endDate) : null;

              // Determine if tournament is active or expired
              const isExpired = endDate && endDate < now;
              statusMap[tournamentId] = isExpired ? "expired" : "active";

              // Add to active tournaments list if it's active
              if (!isExpired) {
                activeTournamentsList.push(tournament);
              }
            } else {
              statusMap[tournamentId] = "unknown";
            }
          } catch (err) {
            console.error(`Failed to fetch tournament ${tournamentId} status:`, err);
            statusMap[tournamentId] = "unknown";
          }
        }

        setTournamentStatusMap(statusMap);
        setActiveTournaments(activeTournamentsList);
      } catch (err) {
        console.error("Failed to fetch tournament statuses:", err);
      }
    };

    fetchNotifications();
  }, []);

  const handleAction = async (notification, action) => {
    if (!notification?._id) return;

    try {
      const decision = action.toLowerCase();

      // Map payment method from Payment schema to Booking schema
      // Payment schema has: card, upi, netbanking, wallet, any, online -> map to 'cash' or 'free' in Booking
      // Booking schema only accepts: cash, free, waived
      let bookingPaymentMethod = 'cash'; // default
      if (notification.paymentMethod && ['card', 'upi', 'netbanking', 'wallet', 'online'].includes(notification.paymentMethod.toLowerCase())) {
        bookingPaymentMethod = 'cash'; // map online payments to cash for booking purposes
      } else if (notification.paymentMethod && ['free', 'waived'].includes(notification.paymentMethod.toLowerCase())) {
        bookingPaymentMethod = notification.paymentMethod.toLowerCase();
      }

      await axios.patch(
        `/api/payments/booking/update-status`,
        {
          tournamentId: notification.tournamentId,
          userId: notification.user._id,
          decision: decision === "accept" ? "accepted" : "rejected",
          paymentMethod: bookingPaymentMethod, // Pass the mapped payment method
        }
      );

      setNotifications((prev) =>
        prev.map((n) =>
          n._id === notification._id
            ? { ...n, status: decision === "accept" ? "accepted" : "rejected" }
            : n
        )
      );
    } catch (err) {
      console.error("Failed to update booking/payment:", err);
    }
  };

  const toggleSelect = (id) => {
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id]
    );
  };

  const bulkAction = async (action) => {
    if (selected.length === 0) return;
    setLoading(true);

    try {
      const items = notifications
        .filter((n) => selected.includes(n._id))
        .map((n) => ({
          userId: n.user._id,
          tournamentId: n.tournamentId,
          // Map payment method from Payment schema to Booking schema
          paymentMethod: n.paymentMethod && ['card', 'upi', 'netbanking', 'wallet', 'online'].includes(n.paymentMethod.toLowerCase())
            ? 'cash'
            : n.paymentMethod && ['free', 'waived'].includes(n.paymentMethod.toLowerCase())
              ? n.paymentMethod.toLowerCase()
              : 'cash' // default
        }));

      await axios.patch(
        `/api/payments/booking/bulk-update`,
        { items, decision: action }
      );

      setNotifications((prev) =>
        prev.map((n) =>
          selected.includes(n._id) ? { ...n, status: action } : n
        )
      );
      setSelected([]);
    } catch (err) {
      console.error("Bulk update failed:", err);
    } finally {
      setLoading(false);
    }
  };

  const getFilteredNotifications = () => {
    let filtered = notifications;

    // If activeTab is 'All', return all notifications
    if (activeTab === "All") {
      return filtered;
    }

    // For tournament-specific tabs, filter by current tournament
    if (activeTab !== "All" && activeTab !== "Payment List") {
      // Filter by the tournament ID which is the activeTab value
      filtered = filtered.filter(n => n.tournamentId === activeTab);

      // Apply payment method filter specific to this tournament tab
      const currentTournamentPaymentFilter = tournamentPaymentFilter[activeTab] || "All";
      if (currentTournamentPaymentFilter !== "All") {
        filtered = filtered.filter(n =>
          n.paymentMethod?.toLowerCase() === currentTournamentPaymentFilter.toLowerCase()
        );
      }
    }

    // If it's the old 'Payment List' tab, use legacy filtering
    if (activeTab === "Payment List") {
      filtered = filtered.filter(
        (n) =>
          n.type === "payment" &&
          (paymentFilter.toLowerCase() === "all" ||
            n.paymentMethod?.toLowerCase() === paymentFilter.toLowerCase())
      );
    }

    return filtered;
  };

  const renderNotification = (n) => (
    <div
      key={n._id}
      className={`flex items-center justify-between p-4 rounded-xl shadow-sm mb-3 transition-all ${selected.includes(n._id)
        ? "bg-blue-50 border border-blue-200"
        : "bg-white hover:shadow-md hover:bg-gray-50"
        }`}
    >
      {/* Checkbox */}
      <input
        type="checkbox"
        checked={selected.includes(n._id)}
        disabled={tournamentStatusMap[n.tournamentId] !== "active"}
        onChange={() => toggleSelect(n._id)}
        className="mr-4 w-4 h-4 accent-blue-600 cursor-pointer disabled:opacity-40"
      />

      {/* Main Info */}
      <div className="flex-1">
        <div className="flex items-center gap-2">
          <p className="font-semibold text-gray-800 text-sm">
            {n.user?.name || "Player"}
          </p>
          {/* Tournament Status Badge */}
          <span
            className={`px-2 py-0.5 rounded-full text-xs font-medium ${tournamentStatusMap[n.tournamentId] === "active"
              ? "bg-green-100 text-green-700"
              : tournamentStatusMap[n.tournamentId] === "expired"
                ? "bg-red-100 text-red-700"
                : "bg-gray-100 text-gray-700"
              }`}
          >
            {tournamentStatusMap[n.tournamentId]?.toUpperCase() || "UNKNOWN"}
          </span>
        </div>
        <p className="text-sm text-gray-600 mt-0.5">{n.message}</p>
        <p className="text-xs text-gray-400 mt-1">
          Transaction ID:{" "}
          <span className="font-mono">{n.registrationId || "N/A"}</span>
          <span className="ml-2">| Tournament: {n.tournamentId}</span>
        </p>
      </div>

      {/* Actions */}
      {n.status === "pending" ? (
        <div className="flex gap-2">
          <button
            onClick={() => handleAction(n, "accept")}
            className="px-4 py-1.5 bg-green-500 text-white text-xs font-medium rounded-full shadow-sm hover:bg-green-600 transition"
          >
            ✅ Accept
          </button>
          <button
            onClick={() => handleAction(n, "reject")}
            className="px-4 py-1.5 bg-red-500 text-white text-xs font-medium rounded-full shadow-sm hover:bg-red-600 transition"
          >
            ❌ Decline
          </button>
        </div>
      ) : (
        <span
          className={`px-4 py-1.5 text-xs font-semibold rounded-full shadow-sm ${n.status === "accepted"
            ? "bg-green-100 text-green-700"
            : "bg-red-100 text-red-700"
            }`}
        >
          {n.status.charAt(0).toUpperCase() + n.status.slice(1)}
        </span>
      )}
    </div>
  );

  const filtered = getFilteredNotifications();
  const allSelected =
    filtered.length > 0 && filtered.every((n) => selected.includes(n._id));

  const toggleSelectAll = () => {
    if (allSelected) {
      setSelected((prev) =>
        prev.filter((id) => !filtered.some((n) => n._id === id))
      );
    } else {
      const idsToAdd = filtered.map((n) => n._id);
      setSelected((prev) => Array.from(new Set([...prev, ...idsToAdd])));
    }
  };

  const clearAllSelections = () => setSelected([]);

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      {/* Main Tabs */}
      <div className="mb-6">
        <div className="flex flex-wrap items-center gap-2 p-2 rounded-xl bg-gray-50 border border-gray-200">
          {["All", ...activeTournaments.map(t => t._id)].map((tab) => {
            const tournament = activeTournaments.find(t => t._id === tab);
            const isActive = activeTab === tab;

            return (
              <div key={tab} className="relative">
                <button
                  onClick={() => setActiveTab(tab)}
                  className={`relative px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 ${isActive
                    ? "bg-blue-600 text-white shadow-md"
                    : "text-gray-600 hover:bg-white hover:text-gray-900"
                    }`}
                >
                  {tab === "All"
                    ? "All Notifications"
                    : tournament?.title || `Tournament ${tab.substring(0, 8)}…`}
                </button>

                {/* Sub-tabs */}
                {tab !== "All" && isActive && (
                  <div className="absolute left-0 mt-3 flex gap-1 rounded-lg bg-white border border-gray-200 shadow-sm p-1 z-10">
                    {["Cash", "Online", "All"].map((method) => {
                      const isSubActive = tournamentPaymentFilter[tab] === method;

                      return (
                        <button
                          key={`sub-${tab}-${method}`}
                          onClick={() =>
                            setTournamentPaymentFilter(prev => ({
                              ...prev,
                              [tab]: method,
                            }))
                          }
                          className={`px-3 py-1.5 rounded-md text-xs font-medium transition ${isSubActive
                            ? "bg-blue-100 text-blue-700"
                            : "text-gray-600 hover:bg-gray-100"
                            }`}
                        >
                          {method}
                        </button>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* Payment filters - only show for the old Payment List tab */}
      {activeTab === "Payment List" && (
        <div className="mb-4 rounded-xl border border-gray-200 bg-white shadow-sm">
          <div className="flex flex-wrap items-center gap-6 px-5 py-4">

            {/* Payment Method */}
            <div className="flex flex-col gap-1">
              <span className="text-xs font-semibold uppercase tracking-wide text-gray-500">
                Payment Method
              </span>

              <div className="inline-flex rounded-lg border border-gray-300 bg-gray-50 p-1">
                {["Online", "Cash", "All"].map((f) => (
                  <button
                    key={f}
                    onClick={() => setPaymentFilter(f)}
                    className={`px-4 py-1.5 text-sm font-medium rounded-md transition ${paymentFilter === f
                        ? "bg-white text-blue-600 shadow-sm"
                        : "text-gray-600 hover:text-gray-900"
                      }`}
                  >
                    {f}
                  </button>
                ))}
              </div>
            </div>

            {/* Tournament Status */}
            <div className="flex flex-col gap-1">
              <span className="text-xs font-semibold uppercase tracking-wide text-gray-500">
                Tournament Status
              </span>

              <div className="inline-flex rounded-lg border border-gray-300 bg-gray-50 p-1">
                {["Active", "Expired", "All"].map((status) => {
                  const value = status.toLowerCase();
                  const isActive =
                    (tournamentStatusFilter === value && status !== "All") ||
                    (tournamentStatusFilter === "all" && status === "All");

                  return (
                    <button
                      key={status}
                      onClick={() =>
                        setTournamentStatusFilter(value === "all" ? "all" : value)
                      }
                      className={`px-4 py-1.5 text-sm font-medium rounded-md transition ${isActive
                          ? "bg-white text-green-600 shadow-sm"
                          : "text-gray-600 hover:text-gray-900"
                        }`}
                    >
                      {status}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Spacer */}
            <div className="flex-1" />

            {/* Tournament Selector */}
            <div className="flex flex-col gap-1 min-w-[220px]">
              <span className="text-xs font-semibold uppercase tracking-wide text-gray-500">
                Tournament
              </span>

              <select
                value={specificTournamentFilter}
                onChange={(e) => setSpecificTournamentFilter(e.target.value)}
                className="w-full rounded-lg border border-gray-300 bg-gray-50 px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="all">All Tournaments</option>
                {[...new Set(notifications.map(n => n.tournamentId))]
                  .filter(Boolean)
                  .map(id => (
                    <option key={id} value={id}>
                      Tournament {id.substring(0, 8)}…
                    </option>
                  ))}
              </select>
            </div>
          </div>
        </div>
      )}

      {/* Select All */}
      {filtered.length > 0 && (
        <div className="flex flex-col gap-3 mb-4 p-2 bg-white rounded shadow-sm">
          <div className="flex items-center gap-3">
            <input
              type="checkbox"
              checked={allSelected}
              onChange={toggleSelectAll}
              className="accent-blue-600 w-4 h-4 cursor-pointer"
            />
            <span className="text-sm text-gray-700">
              {allSelected ? "Unselect All" : "Select All"} ({filtered.length})
            </span>
            {selected.length > 0 && (
              <button
                onClick={clearAllSelections}
                className="ml-auto text-sm text-red-500 hover:underline"
              >
                Clear Selection
              </button>
            )}
          </div>
          {/* Tournament Status Summary */}
          <div className="flex gap-4 text-xs text-gray-600">
            <span className="flex items-center gap-1">
              <span className="w-3 h-3 rounded-full bg-green-100 border border-green-300"></span>
              Active Tournaments: {
                filtered.filter(n => tournamentStatusMap[n.tournamentId] === 'active').length
              }
            </span>
            <span className="flex items-center gap-1">
              <span className="w-3 h-3 rounded-full bg-red-100 border border-red-300"></span>
              Expired Tournaments: {
                filtered.filter(n => tournamentStatusMap[n.tournamentId] === 'expired').length
              }
            </span>
          </div>
        </div>
      )}

      {/* Notifications */}
      <div className="flex-1 overflow-y-auto">{filtered.map(renderNotification)}</div>

      {/* Bulk Action Bar */}
      {selected.length > 0 && (
        <div className="fixed bottom-5 left-1/2 -translate-x-1/2 bg-white shadow-lg border rounded-full px-6 py-2 flex flex-col sm:flex-row gap-2 sm:gap-4 items-center z-50">
          <div className="flex items-center gap-2">
            <span className="text-sm text-gray-600">
              {selected.length} selected
            </span>
            {/* Warning if expired tournaments are selected */}
            {notifications
              .filter(n => selected.includes(n._id))
              .some(n => tournamentStatusMap[n.tournamentId] === "expired") && (
                <span className="text-xs bg-yellow-100 text-yellow-700 px-2 py-1 rounded">
                  Contains expired tournament entries
                </span>
              )}
          </div>
          <div className="flex gap-2">
            <button
              onClick={() => bulkAction("accepted")}
              className="px-4 py-1 bg-green-500 text-white rounded-full text-sm hover:bg-green-600 disabled:opacity-50"
              disabled={loading}
            >
              Accept
            </button>
            <button
              onClick={() => bulkAction("rejected")}
              className="px-4 py-1 bg-red-500 text-white rounded-full text-sm hover:bg-red-600 disabled:opacity-50"
              disabled={loading}
            >
              Reject
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

