        const calculatedTotalRounds = Math.ceil(Math.log2(totalTeams));

        console.log("📊 Tournament Statistics:");
        console.log("- Total teams:", totalTeams);
        console.log("- Calculated total rounds:", calculatedTotalRounds);
        console.log(
