                        : "bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 text-white"
                        }`}
                    >
                      {isFinalsNext && <FaTrophy className="w-4 h-4" />}
                      <RefreshCcw className="w-4 h-4" />
