                            </p>
                            <div className="flex justify-between text-sm">
                              <span className="text-blue-600">
                                {players.teamA.player2} (C)
                              </span>
                              <span className="text-gray-500">vs</span>
                              <span className="text-red-600">
                                {players.teamB.player2} (Z)
                              </span>
                            </div>
