      const teamId = team === "team1" ? "home_team_id" : "away_team_id"; // You'll need actual team IDs

      const response = await fetch(
        `/api/tournaments/team-knockout/teams/${teamId}/substitute`,
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
