      );

      if (!response.ok) {
        throw new Error("Failed to make substitution");
      }

      const data = await response.json();
      console.log("Substitution successful:", data);

      // Refresh match data
      await initializeMatch();

      showModal("Success", "Player substitution completed successfully");
