        );

        if (response.ok) {
          setMatches(updatedMatches);
          setRefreshTrigger((prev) => prev + 1);
          setSelectedGame(null);
          showModal("Success", "Score updated successfully");
        } else {
          throw new Error("Failed to update scores");
        }
