          <p className="text-green-600 mt-3 font-medium">{success}</p>
        )}
      </div>

      <div className="bg-gray-50 p-6 rounded-xl shadow-inner">
        <h4 className="text-xl font-semibold text-gray-700 mb-4">
          Available Sports
        </h4>
        <div className="overflow-x-auto">
          <table className="min-w-full text-sm text-center border border-gray-200 rounded-md overflow-hidden">
            <thead className="bg-gray-100 text-gray-700">
              <tr>
                <th className="p-3 border">Sr.No</th>
                <th className="p-3 border">Sport</th>
                <th className="p-3 border">Status</th>
                <th className="p-3 border">Action</th>
              </tr>
            </thead>
            <tbody className="bg-white">
              {sports.map((sport, index) => (
                <tr key={sport._id} className="hover:bg-gray-50 transition">
                  <td className="p-3 border">{index + 1}</td>
                  <td className="p-3 border capitalize">{sport.name}</td>
                  <td className="p-3 border">
                    <span
                      className={`inline-block w-[80px] text-center px-3 py-1 text-xs font-medium rounded-full ${
                        sport.isActive
                          ? "bg-green-100 text-green-700"
                          : "bg-red-100 text-red-700"
                      }`}
                    >
                      {sport.isActive ? "Active" : "Inactive"}
                    </span>
                  </td>
                  <td className="p-3 border">
                    <button
                      onClick={() =>
                        toggleSportStatus(sport._id, sport.isActive)
                      }
                      className={`min-w-[120px] w-fit px-5 py-2 rounded-lg text-sm font-semibold text-white transition-colors duration-300
      ${
        sport.isActive
          ? "bg-red-600 hover:bg-red-700"
          : "bg-green-600 hover:bg-green-700"
      }`}
                    >
                      {sport.isActive ? "Deactivate" : "Activate"}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

