      {sessions.length === 0 ? (
        <div
          className="rounded-lg shadow-md p-8 text-center"
          style={{ backgroundColor: colors.white }}
        >
          <div
            className="rounded-full h-20 w-20 flex items-center justify-center mx-auto mb-4"
            style={{ backgroundColor: colors.primaryLight }}
          >
            <FaHistory size={30} style={{ color: colors.primary }} />
          </div>
          <h2
            className="text-xl font-semibold mb-2"
            style={{ color: colors.text }}
          >
            No Session History
          </h2>
          <p className="mb-6" style={{ color: colors.textLight }}>
            You don't have any completed training sessions yet.
          </p>
          <Link
            to="/trainer-sessions"
            className="inline-block px-4 py-2 rounded-lg"
            style={{ backgroundColor: colors.primary, color: colors.white }}
          >
            View All Sessions
          </Link>
        </div>
      ) : filteredSessions.length === 0 ? (
        <div
          className="rounded-lg shadow-md p-8 text-center"
          style={{ backgroundColor: colors.white }}
        >
          <div
            className="rounded-full h-20 w-20 flex items-center justify-center mx-auto mb-4"
            style={{ backgroundColor: colors.primaryLight }}
          >
            <FaSearch size={30} style={{ color: colors.primary }} />
          </div>
          <h2
            className="text-xl font-semibold mb-2"
            style={{ color: colors.text }}
          >
            No Matching Sessions
          </h2>
          <p className="mb-6" style={{ color: colors.textLight }}>
            No sessions match your current filters.
          </p>
          <button
            onClick={() => {
              setSearchTerm("");
              setTypeFilter("all");
              setDateFilter("all");
            }}
            className="inline-block px-4 py-2 rounded-lg"
            style={{ backgroundColor: colors.primary, color: colors.white }}
          >
            Clear Filters
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Sessions List */}
          <div className="lg:col-span-1">
            <div
              className="rounded-lg shadow-md overflow-hidden"
              style={{ backgroundColor: colors.white }}
            >
              <div
                className="p-4 flex justify-between items-center"
                style={{ borderBottom: `1px solid ${colors.border}` }}
              >
                <h2
                  className="text-lg font-semibold"
                  style={{ color: colors.text }}
                >
                  Completed Sessions
                </h2>
                <div
                  className="text-sm px-2 py-1 rounded-full"
                  style={{
                    backgroundColor: colors.primaryLight,
                    color: colors.primary,
                  }}
                >
                  {filteredSessions.length}
                </div>
              </div>

              <div className="overflow-y-auto" style={{ maxHeight: "70vh" }}>
                {filteredSessions.map((session) => (
                  <div
                    key={session._id}
                    className="p-4 cursor-pointer transition-colors"
                    style={{
                      borderBottom: `1px solid ${colors.border}`,
                      backgroundColor:
                        selectedSession && selectedSession._id === session._id
                          ? colors.primaryLight
                          : colors.white,
                    }}
                    onClick={() => setSelectedSession(session)}
                  >
                    <div>
                      <p className="font-medium" style={{ color: colors.text }}>
                        {session.title}
                      </p>
                      <p
                        className="text-sm"
                        style={{ color: colors.textLight }}
                      >
                        {formatDate(session.startTime)}
                      </p>
                      <div className="flex items-center mt-1">
                        <span
                          className="inline-block text-xs px-2 py-1 rounded-full capitalize mr-2"
                          style={{
                            backgroundColor: colors.primaryLight,
                            color: colors.primary,
                          }}
                        >
                          {session.type}
                        </span>
                        <span
                          className="text-xs"
                          style={{ color: colors.textLight }}
                        >
                          {session.location}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* Session Details */}
          <div className="lg:col-span-2">
            {selectedSession ? (
              <div
                className="rounded-lg shadow-md overflow-hidden"
                style={{ backgroundColor: colors.white }}
              >
                <div
                  className="px-6 py-4"
                  style={{ borderBottom: `1px solid ${colors.border}` }}
                >
                  <h2
                    className="text-lg font-semibold"
                    style={{ color: colors.text }}
                  >
                    Session Details
                  </h2>
                </div>

                <div className="p-6">
                  <div className="flex items-center mb-6">
                    <div
                      className="rounded-full p-3 mr-4"
                      style={{ backgroundColor: colors.primaryLight }}
                    >
                      <FaHistory size={18} style={{ color: colors.primary }} />
                    </div>
                    <div>
                      <h3
                        className="text-xl font-semibold"
                        style={{ color: colors.text }}
                      >
                        {selectedSession.title}
                      </h3>
                      <span
                        className="text-xs px-2 py-1 rounded-full capitalize"
                        style={{
                          backgroundColor: colors.primaryLight,
                          color: colors.primary,
                        }}
                      >
                        {selectedSession.type} Session
                      </span>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    <div>
                      <h3
                        className="font-semibold mb-2 flex items-center"
                        style={{ color: colors.text }}
                      >
                        <FaCalendar
                          className="mr-2"
                          style={{ color: colors.primary }}
                        />
                        Session Information
                      </h3>
                      <div
                        className="rounded-lg p-4"
                        style={{ backgroundColor: colors.background }}
                      >
                        <p className="flex items-center mb-3">
                          <FaCalendar
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                          <span className="font-medium">Date:</span>
                          <span
                            className="ml-2"
                            style={{ color: colors.textLight }}
                          >
                            {formatDate(selectedSession.startTime)}
                          </span>
                        </p>
                        <p className="flex items-center mb-3">
                          <FaClock
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                          <span className="font-medium">Time:</span>
                          <span
                            className="ml-2"
                            style={{ color: colors.textLight }}
                          >
                            {formatTime(selectedSession.startTime)} -{" "}
                            {formatTime(selectedSession.endTime)}
                          </span>
                        </p>
                        <p className="flex items-center">
                          <FaMapMarkerAlt
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                          <span className="font-medium">Location:</span>
                          <span
                            className="ml-2"
                            style={{ color: colors.textLight }}
                          >
                            {selectedSession.location}
                          </span>
                        </p>
                      </div>
                    </div>

                    <div>
                      <h3
                        className="font-semibold mb-2 flex items-center"
                        style={{ color: colors.text }}
                      >
                        {selectedSession.type === "individual" ? (
                          <FaUser
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                        ) : selectedSession.type === "club" ? (
                          <FaBuilding
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                        ) : (
                          <FaUsers
                            className="mr-2"
                            style={{ color: colors.primary }}
                          />
                        )}
                        Participant Information
                      </h3>
                      <div
                        className="rounded-lg p-4"
                        style={{ backgroundColor: colors.background }}
                      >
                        {selectedSession.type === "individual" &&
                        selectedSession.playerId ? (
                          <p>
                            <span className="font-medium">Player:</span>{" "}
                            <span style={{ color: colors.textLight }}>
                              {selectedSession.playerName ||
                                "Player information not available"}
                            </span>
                          </p>
                        ) : selectedSession.type === "club" &&
                          selectedSession.clubId ? (
                          <p>
                            <span className="font-medium">Club:</span>{" "}
                            <span style={{ color: colors.textLight }}>
                              {selectedSession.clubName ||
                                "Club information not available"}
                            </span>
                          </p>
                        ) : (
                          <p style={{ color: colors.textLight }}>
                            No participant information available
                          </p>
                        )}
                      </div>
                    </div>
                  </div>

                  {selectedSession.notes && (
                    <div className="mb-6">
                      <h3
                        className="font-semibold mb-2 flex items-center"
                        style={{ color: colors.text }}
                      >
                        <FaClipboardList
                          className="mr-2"
                          style={{ color: colors.primary }}
                        />
                        Session Notes
                      </h3>
                      <div
                        className="rounded-lg p-4"
                        style={{ backgroundColor: colors.background }}
                      >
                        <p style={{ color: colors.textLight }}>
                          {selectedSession.notes}
                        </p>
                      </div>
                    </div>
                  )}

                  <div>
                    <h3
                      className="font-semibold mb-2 flex items-center"
                      style={{ color: colors.text }}
                    >
                      <FaChartBar
                        className="mr-2"
                        style={{ color: colors.primary }}
                      />
                      Session Metrics
                    </h3>
                    <div
                      className="rounded-lg p-4"
                      style={{ backgroundColor: colors.background }}
                    >
                      <div className="grid grid-cols-2 gap-6">
                        <div>
                          <p
                            className="text-sm"
                            style={{ color: colors.textLight }}
                          >
                            Duration
                          </p>
                          <p
                            className="font-medium"
                            style={{ color: colors.text }}
                          >
                            {selectedSession.endedAt &&
                            selectedSession.startedAt
                              ? `${Math.round(
                                  (new Date(selectedSession.endedAt) -
                                    new Date(selectedSession.startedAt)) /
                                    (1000 * 60)
                                )} mins`
                              : `${Math.round(
                                  (new Date(selectedSession.endTime) -
                                    new Date(selectedSession.startTime)) /
                                    (1000 * 60)
                                )} mins (scheduled)`}
                          </p>
                        </div>
                        <div>
                          <p
                            className="text-sm"
                            style={{ color: colors.textLight }}
                          >
                            Completed On
                          </p>
                          <p
                            className="font-medium"
                            style={{ color: colors.text }}
                          >
                            {selectedSession.endedAt
                              ? formatDate(selectedSession.endedAt)
                              : "Not recorded"}
                          </p>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ) : (
              <div
                className="rounded-lg shadow-md p-6 text-center"
                style={{ backgroundColor: colors.white }}
              >
                <div className="py-12">
                  <div
                    className="rounded-full h-20 w-20 flex items-center justify-center mx-auto mb-4"
                    style={{ backgroundColor: colors.background }}
                  >
                    <FaHistory size={30} style={{ color: colors.textLight }} />
                  </div>
                  <h3
                    className="text-lg font-medium mb-2"
                    style={{ color: colors.text }}
                  >
                    No Session Selected
                  </h3>
                  <p className="mb-4" style={{ color: colors.textLight }}>
                    Select a session from the list to view details
                  </p>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

