  FaUserAlt,
  FaCalendarCheck,
  FaCalendarTimes,
  FaCheck,
  FaTimes,
  FaFilter,
  FaSearch,
} from "react-icons/fa";

// Color scheme with green as primary (matching TrainerSessions)
const colors = {
  background: "#F5F6FA",
  white: "#FFFFFF",
  primary: "#36B37E", // Green primary
  primaryLight: "#E3FCEF", // Light green for backgrounds
  primaryDark: "#00875A", // Darker green for hover states
  text: "#172B4D", // Dark blue-gray for text
  textLight: "#6B778C", // Lighter text color
  border: "#DFE1E6",
  success: "#36B37E",
  danger: "#FF5630",
};

const TrainerPlayerRequests = () => {
  const { user, isAuthenticated } = useContext(AuthContext);
  const [requests, setRequests] = useState([]);
  const [selectedRequest, setSelectedRequest] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [statusFilter, setStatusFilter] = useState("pending");
  const [searchTerm, setSearchTerm] = useState("");

  // Fallback player requests data
  const fallbackPlayerRequests = [
    {
      _id: "fallback-1",
      type: "player",
      playerName: "Emily Johnson",
      status: "pending",
      sessionType: "individual",
      requestedDate: new Date(
        Date.now() + 7 * 24 * 60 * 60 * 1000
      ).toLocaleDateString(),
      requestedTime: "14:00",
      createdAt: new Date().toISOString(),
      location: "Main Training Center",
      notes: "Looking to improve strength and conditioning",
    },
    {
      _id: "fallback-2",
      type: "player",
      playerName: "Michael Rodriguez",
      status: "accepted",
      sessionType: "group",
      requestedDate: new Date(
        Date.now() + 14 * 24 * 60 * 60 * 1000
      ).toLocaleDateString(),
      requestedTime: "16:30",
      createdAt: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000).toISOString(),
      location: "Sports Complex",
      notes: "Team training preparation",
    },
    {
      _id: "fallback-3",
      type: "player",
      playerName: "Sarah Kim",
      status: "rejected",
      sessionType: "individual",
      requestedDate: new Date(
        Date.now() + 21 * 24 * 60 * 60 * 1000
      ).toLocaleDateString(),
      requestedTime: "10:00",
      createdAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000).toISOString(),
      location: "Community Sports Center",
      notes: "Interested in joining training program",
    },
  ];

  // Modify fetchPlayerRequests logic in useEffect
  useEffect(() => {
    const fetchPlayerRequests = async () => {
      try {
        if (!isAuthenticated || !user) {
          throw new Error("User not authenticated");
        }

        try {
          const response = await axios.get(
            `${import.meta.env.VITE_API_BASE_URL}/trainer/requests/${user.id}`
          );

          // Filter for player requests
          const playerRequests =
            response.data.length > 0
              ? response.data.filter((request) => request.type === "player")
              : fallbackPlayerRequests;

          // Sort by creation date (newest first)
          playerRequests.sort(
            (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
          );

          setRequests(playerRequests);
          setLoading(false);
        } catch (apiError) {
          console.warn("API error, using fallback player requests:", apiError);
          setRequests(fallbackPlayerRequests);
          setLoading(false);
        }
      } catch (err) {
        console.error("Error details:", err.response?.data || err);
        setError(err.response?.data?.message || err.message);
        setLoading(false);
      }
    };

    if (isAuthenticated && user && user.id) {
      fetchPlayerRequests();
    }
  }, [user, isAuthenticated]);

  // useEffect(() => {
  //   const fetchPlayerRequests = async () => {
  //     try {
  //       if (!isAuthenticated || !user) {
  //         throw new Error("User not authenticated");
  //       }

  //       const response = await axios.get(
  //         `${import.meta.env.VITE_API_BASE_URL}/trainer/requests/${user.id}`
  //       );

  //       // Filter for player requests only
  //       const playerRequests = response.data.filter(
  //         (request) => request.type === "player"
  //       );

  //       // Sort by creation date (newest first)
  //       playerRequests.sort(
  //         (a, b) => new Date(b.createdAt) - new Date(a.createdAt)
  //       );

  //       setRequests(playerRequests);
  //       setLoading(false);
  //     } catch (err) {
  //       setError(err.response?.data?.message || err.message);
  //       setLoading(false);
  //     }
  //   };

  //   if (isAuthenticated && user && user.id) {
  //     fetchPlayerRequests();
  //   }
  // }, [user, isAuthenticated]);

  const handleAccept = async (id) => {
    try {
      await axios.put(
        `${import.meta.env.VITE_API_BASE_URL}/trainer/requests/${id}/accept`,
        {},
        {
          headers: { "Content-Type": "application/json" },
        }
      );

      // Refresh requests
      const response = await axios.get(
        `${import.meta.env.VITE_API_BASE_URL}/trainer/requests/${user.id}`
      );
      const playerRequests = response.data.filter(
        (request) => request.type === "player"
