import React, { useState, useEffect, useContext } from "react";
import { AuthContext } from "../context/AuthContext";
import axios from "axios";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";

const TrainerProfile = () => {
  const { auth } = useContext(AuthContext);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState("personal");

  // Form state
  const [formData, setFormData] = useState({
    firstName: "",
    lastName: "",
    dob: "",
    gender: "",
    sport: "",
    experience: "",
    address: "",
    emergencyContact: "",
    emergencyContactName: "",
    about: "",
  });

  // Certificate state
  const [newCertificate, setNewCertificate] = useState({
    name: "",
    issuedBy: "",
    issueDate: "",
    expiryDate: "",
    certificateId: "",
  });

  // Fetch trainer profile
  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const response = await axios.get(
          `${import.meta.env.VITE_API_BASE_URL}/trainer/profile/${auth._id}`
        );
        setProfile(response.data);

        // Initialize form with profile data
        if (response.data) {
          setFormData({
            firstName: response.data.firstName || "",
            lastName: response.data.lastName || "",
            dob: response.data.dob
              ? new Date(response.data.dob).toISOString().split("T")[0]
              : "",
            gender: response.data.gender || "",
            sport: response.data.sport || "",
            experience: response.data.experience || "",
            address: response.data.address || "",
            emergencyContact: response.data.emergencyContact || "",
            emergencyContactName: response.data.emergencyContactName || "",
            about: response.data.about || "",
          });
        }

        setLoading(false);
      } catch (error) {
        console.error("Error fetching profile:", error);
        toast.error("Failed to load profile data");
        setLoading(false);
      }
    };

    if (auth && auth._id) {
      fetchProfile();
    }
  }, [auth]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  const handleCertificateChange = (e) => {
    const { name, value } = e.target;
    setNewCertificate({
      ...newCertificate,
      [name]: value,
    });
  };

  const handleProfileUpdate = async () => {
    try {
      const response = await axios.put(
        `/api/trainers/profile/${auth._id}`,
        formData
      );
      setProfile(response.data);
      toast.success("Profile updated successfully");
    } catch (error) {
      console.error("Error updating profile:", error);
      toast.error("Failed to update profile");
    }
  };

  const handleAddCertificate = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post(
        `/api/trainers/certificate/${auth._id}`,
        newCertificate
      );
      setProfile({
        ...profile,
        certificates: response.data,
      });
      setNewCertificate({
        name: "",
        issuedBy: "",
        issueDate: "",
        expiryDate: "",
        certificateId: "",
      });
      toast.success("Certificate added successfully");
    } catch (error) {
      console.error("Error adding certificate:", error);
      toast.error("Failed to add certificate");
    }
  };

  const handleRemoveCertificate = async (certId) => {
    try {
      const response = await axios.delete(
        `/api/trainers/certificate/${auth._id}/${certId}`
      );
      setProfile({
        ...profile,
        certificates: response.data,
      });
      toast.success("Certificate removed successfully");
    } catch (error) {
      console.error("Error removing certificate:", error);
      toast.error("Failed to remove certificate");
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  return (
    <div className="bg-white min-h-screen p-6">
      <div className="max-w-4xl mx-auto">
        {/* Profile Header */}
        <div className="flex items-center mb-8">
          <div className="w-24 h-24 rounded-full bg-blue-500 flex items-center justify-center text-white text-2xl font-bold mr-6">
            {profile?.firstName?.[0] || ""}
            {profile?.lastName?.[0] || ""}
          </div>
          <div>
            <h1 className="text-2xl font-bold">
              {profile?.firstName || ""} {profile?.lastName || ""}
            </h1>
            <p className="text-gray-600">
              {profile?.sport ? `${profile.sport} Trainer` : "Trainer"}
            </p>
            <p className="text-gray-600">{auth.email}</p>
          </div>
        </div>

        {/* Tab Navigation */}
        <div className="border-b mb-6">
          <div className="flex space-x-8">
            <button
