                      <h3 className="font-medium">{cert.name}</h3>
                      <p className="text-sm text-gray-600">
                        Issued by: {cert.issuedBy}
                      </p>
                      <p className="text-sm text-gray-600">
                        Date: {new Date(cert.issueDate).toLocaleDateString()}
                        {cert.expiryDate &&
                          ` - Expires: ${new Date(
                            cert.expiryDate
                          ).toLocaleDateString()}`}
                      </p>
                    </div>
                    <button
                      onClick={() => handleRemoveCertificate(cert._id)}
                      className="text-red-500 hover:text-red-700"
                    >
                      Remove
                    </button>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-gray-500 mb-6">No certificates added yet.</p>
            )}

            {/* Add new certificate form */}
            <div className="bg-gray-50 p-4 rounded border">
              <h3 className="font-medium mb-3">Add New Certificate</h3>
              <form
                onSubmit={handleAddCertificate}
                className="grid grid-cols-1 md:grid-cols-2 gap-4"
              >
                <div>
                  <label className="block text-gray-700 mb-1">
                    Certificate Name
                  </label>
                  <input
                    type="text"
                    name="name"
                    value={newCertificate.name}
                    onChange={handleCertificateChange}
                    required
                    className="w-full p-2 border rounded"
                  />
                </div>
                <div>
                  <label className="block text-gray-700 mb-1">
                    Issuing Organization
                  </label>
                  <input
                    type="text"
                    name="issuedBy"
                    value={newCertificate.issuedBy}
                    onChange={handleCertificateChange}
                    required
                    className="w-full p-2 border rounded"
                  />
                </div>
                <div>
                  <label className="block text-gray-700 mb-1">Issue Date</label>
                  <input
                    type="date"
                    name="issueDate"
                    value={newCertificate.issueDate}
                    onChange={handleCertificateChange}
                    required
                    className="w-full p-2 border rounded"
                  />
                </div>
                <div>
                  <label className="block text-gray-700 mb-1">
                    Expiry Date (if applicable)
                  </label>
                  <input
                    type="date"
                    name="expiryDate"
                    value={newCertificate.expiryDate}
                    onChange={handleCertificateChange}
                    className="w-full p-2 border rounded"
                  />
                </div>
                <div>
                  <label className="block text-gray-700 mb-1">
                    Certificate ID (optional)
                  </label>
                  <input
                    type="text"
                    name="certificateId"
                    value={newCertificate.certificateId}
                    onChange={handleCertificateChange}
                    className="w-full p-2 border rounded"
                  />
                </div>
                <div className="flex items-end">
                  <button
                    type="submit"
                    className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
                  >
                    Add Certificate
                  </button>
                </div>
              </form>
            </div>
          </div>
        )}
      </div>
      <ToastContainer />
    </div>
  );
};

